UPDATE sites SET nombre_en = 'Place for doubts', tipo_en = 'Art Space', descripcion_en = 'In the vibrant Granada neighborhood, a traditional Cali house hides an unparalleled laboratory of artistic thought. Lugar a Dudas is not a static museum, but a dynamic space dedicated to the research, production and dissemination of contemporary artistic practices. Founded by renowned artist Oscar Muñoz, this center has an international residency program, experimental exhibition halls, and a specialized documentation center. Here art is questioned, debated and produced, becoming a mandatory stop for curators, artists and global thinkers.', importancia_en = 'Founded by the teacher Oscar Muñoz, it is an international reference for contemporary and conceptual art.', datos_historicos_en = 'It opened its doors in 2005 to fill the void of independent spaces in the city.', datos_curiosos_en = ARRAY['Its name invites ''doubt'' as a method of knowledge.', 'It offers ''Cinema Without an Author'', free screenings and debates in the street.']::text[] WHERE id = 's4';

UPDATE sites SET nombre_en = 'La Merced Archaeological Museum', tipo_en = 'Museo', descripcion_en = 'Located in the oldest colonial building in Santiago de Cali, this museum offers a deep journey into the pre-Hispanic roots of the region. Its thick adobe walls and clay tiles house an impressive collection of ceramics, metalwork and lithic art from the cultures that inhabited southwestern Colombia, such as Calima, Quimbaya, Tumaco and San Agustín. The central courtyard, adorned with a fountain and lush gardens, offers an almost mystical silence in the midst of the hustle and bustle of the center, transporting the visitor to the time of the city''s founding.', importancia_en = 'It preserves the oldest archaeological and architectural heritage of the city.', datos_historicos_en = 'The religious complex dates back to the founding of the city in the 16th century. The museum was established in 1979.', datos_curiosos_en = ARRAY['The first founding mass of Cali was celebrated in this place.', 'It has funerary urns and pre-Columbian printing rollers.']::text[] WHERE id = 's12';

UPDATE sites SET nombre_en = 'Calima Gold Museum', tipo_en = 'Museo', descripcion_en = 'Under the administration of the Bank of the Republic, in the historic center, the Calima Gold Museum preserves the brilliance of the cultures that inhabited this valley thousands of years before Cali had a name. Its collection brings together pieces of goldsmithing, ceramics, stone, wood and shell from the Ilama, Yotoco and Sonso societies - grouped under the generic name of Calima culture -, people who were exceptional farmers and, above all, goldsmiths of a skill that still baffles today. 

To travel through it is to understand that the territory we walk on today had a symbolic and technical density prior to any colonial plaza. The museum works with “pedagogical animators” instead of guides, lends educational kits to schools and maintains animations and exhibitions so that the pre-Hispanic past does not feel distant but rather its own.', importancia_en = 'Main window to the pre-Hispanic legacy of Valle del Cauca and key piece of the Valle del Cauca identity; part of the network of gold museums of the Banco de la República.', datos_historicos_en = 'Inaugurated on May 9, 1991 with the aim of preserving, researching and disseminating the archaeological heritage of the region. It is integrated into the Cultural Center of the Banco de la República in Cali, which includes a library and exhibition rooms.', datos_curiosos_en = ARRAY['Its collection includes pieces of goldsmithing and pottery up to 2,000 years old from the Ilama, Yotoco and Sonso cultures.', 'In the Calima area, northwest of Cali, archeology has recovered more than 9,000 years of human history.', 'It lends “teaching suitcases” to educational institutions to set up small exhibitions in the classroom.']::text[] WHERE id = 's10';

UPDATE sites SET nombre_en = 'Casa Obeso Mejía', tipo_en = 'Museo', descripcion_en = 'A Californian colonial-style house that seems frozen in time, strategically located in front of the Cali River and the famous Gato de Tejada. Originally a family residence of the Cali elite, today it is an intimate cultural space that hosts temporary exhibitions, workshops and private events. Its spacious and perfectly maintained rear gardens are an open secret for enjoying the afternoon breeze and offer a privileged view of the river.', importancia_en = 'Example of domestic architecture from the beginning of the 20th century, today democratized for art.', datos_historicos_en = 'Built by the Obeso Mejía family, it was acquired and restored by the La Tertulia Museum.', datos_curiosos_en = ARRAY['It preserves the original floors, bathrooms and kitchen from the period.', 'Its architecture dialogues with the Obelisco Hotel across the river.']::text[] WHERE id = 's23';

UPDATE sites SET nombre_en = 'Museum of Natural Sciences', tipo_en = 'Museo', descripcion_en = 'A fascinating space to understand the immense biodiversity of one of the richest regions on the planet. Located in the Manzana del Saber, this museum exhibits complete zoological, geological and archaeological collections from the Valle del Cauca. From towering skeletons of prehistoric megafauna to detailed dioramas of local ecosystems (moorland, jungle, sea), it is a must-see educational site for families and nature lovers.', importancia_en = 'INCIVA''s main scientific dissemination center.', datos_historicos_en = 'Founded in 1963 by the biologist Federico Carlos Lehmann.', datos_curiosos_en = ARRAY['It has a complete skeleton of a Mastodon found in the Valley.', 'It has a large collection of taxidermied birds.']::text[] WHERE id = 's30';

UPDATE sites SET nombre_en = 'Hacienda Cañasgordas', tipo_en = 'Historical Estate', descripcion_en = 'A direct trip to the colonial past of Valle del Cauca. This magnificent 18th century hacienda is the real setting where the novel ''El Alférez Real'' by Eustaquio Palacios takes place. Its architecture preserves the wide corridors, the private chapel and the irrigation ditch systems of the time. It is a living testimony of colonial aristocratic life and the history of independence in the region.', importancia_en = 'National Monument and key literary scene of the region.', datos_historicos_en = 'It was the headquarters of the patriot armies during the independence campaign.', datos_curiosos_en = ARRAY['It is said that it still preserves original furniture from the colonial era.', 'Its original lands covered much of the south of present-day Cali.']::text[] WHERE id = 's35';

UPDATE sites SET nombre_en = 'Phoenix Air Museum', tipo_en = 'Museo', descripcion_en = 'Strategically located near the Alfonso Bonilla Aragón airport, this museum is the dream come true of a passionate pilot. Large hangars house historic royal aircraft, from World War II fighter aircraft to executive jets and civilian light aircraft, many of them restored to flying condition. It also features an impressive functional model railway model and a collection of flight suits. It is a unique immersive experience for engineering and aviation lovers.', importancia_en = 'Only museum in Colombia with historical aircraft in flight condition.', datos_historicos_en = 'Founded by Captain Raymond Lee, who recovered many of the aircraft.', datos_curiosos_en = ARRAY['The Douglas DC-3 aircraft is immaculate and you can enter it.', 'The train model is one of the largest and most detailed in Latin America.']::text[] WHERE id = 's50';

UPDATE sites SET nombre_en = 'Caliwood Museum', tipo_en = 'Museo', descripcion_en = 'It all started with two projectors rescued from the trash—the same ones that had been used at the inauguration of the Jorge Isaacs Theater. From that wonderful coincidence, as its founder calls it, Caliwood was born, the first museum of cinematography in Colombia. Hugo Suárez Fiat, a lawyer and collector from Cali, gathered cameras, projectors, magic lanterns and posters that reconstruct the evolution of cinema and photography, from daguerreotypes of 1840 to projectors of the early 20th century. 

The name says it all: Caliwood is the nod to the irreverent cinema movement that Cali gave to the country in the seventies and eighties, with Luis Ospina, Carlos Mayolo and Andrés Caicedo at the helm. Walking through it is entering a time capsule of the seventh art, and a stubborn commitment to preserve the film memory of the city considered the mecca of Colombian cinema.', importancia_en = 'First museum of cinematography in Colombia and guardian of Caliwood''s film memory; unique collection in the country.', datos_historicos_en = 'Legally founded on October 22, 2008 by Hugo Suárez Fiat and opened to the public in 2012, after years of adaptation. It is a private non-profit foundation. It is located on Avenida Belalcázar, Arboleda neighborhood, near Gato de Tejada and La Tertulia.', datos_curiosos_en = ARRAY['It keeps 30 original still photos from the filming of María (1922), the first Colombian film.', 'It was the first museum institution in the country to offer audio guides via QR codes.', 'His collection started with two projectors used at the inauguration of the Jorge Isaacs Theater.']::text[] WHERE id = 's34';

UPDATE sites SET nombre_en = 'Cane Museum', tipo_en = 'Museo', descripcion_en = 'An extensive open-air museum that tells the sweet, complex and transformative history of the agro-industrial development of Valle del Cauca. Located in the historic Hacienda Piedechinche, it offers a tour between beautiful botanical gardens and exhibitions of old trapiches (cane mills) brought from all regions of Colombia. It shows the technological evolution from animal traction and water mills to the modern sugar industry.', importancia_en = 'It preserves the memory of the agribusiness that defined the region''s economy.', datos_historicos_en = 'Founded in 1981. The hacienda house dates back to the 18th century and is a colonial jewel.', datos_curiosos_en = ARRAY['You can see how panela was made by hand.', 'Its gardens are a sanctuary for birds and native flora.']::text[] WHERE id = 's74';

UPDATE sites SET nombre_en = 'MULI - Free Museum of Public Art', tipo_en = 'Art Museum', descripcion_en = 'The largest museum in Colombia, because its roof is the sky. The MULI transformed Cali into an open-air gallery, managing hundreds of artistic murals and mosaics on bridges, buildings and streets. Its main headquarters offers exhibitions, but its real collection is scattered throughout the city, especially in the north. It is an initiative that seeks to democratize art and beautify the urban environment.', importancia_en = 'Pioneer in the massive management of urban art and muralism in the city.', datos_historicos_en = 'It emerged in 2012 for the Summit of the Americas, intervening in the gray spaces of the city.', datos_curiosos_en = ARRAY['They organize the Cali International Muralism Biennial.', 'Many murals incorporate recycled materials and mosaic techniques.']::text[] WHERE id = 's75';

UPDATE sites SET nombre_en = 'The Mask Theater', tipo_en = 'Experimental Theater', descripcion_en = 'Located in the heart of the bohemian and heritage San Antonio neighborhood, La Máscara is a historical benchmark of independent and socially committed theater. It operates in a beautiful adapted colonial house that offers an intimate and close atmosphere between actors and audience. She specializes in theater with a gender focus and experimental proposals that challenge the viewer, promoting debate and reflection. It is a vibrant place where art and social activism meet.', importancia_en = 'Pioneers in theater made by women and with themes of diversity and gender in the region.', datos_historicos_en = 'Founded in 1972, it is one of the oldest and most persistent theater groups in the city, surviving for decades thanks to its quality.', datos_curiosos_en = ARRAY['They annually organize an international festival of women on stage.', 'Its room allows for a very direct, almost visceral interaction with the actors.']::text[] WHERE id = 's14';

UPDATE sites SET nombre_en = 'Enrique Buenaventura Municipal Theater', tipo_en = 'Theater', descripcion_en = 'The Enrique Buenaventura Municipal Theater is the ultimate jewel of culture and scenic architecture in southwestern Colombia. Inaugurated in 1927 with plans inspired by classical Italian opera, the theater boasts a monumental neoclassical façade and a horseshoe-shaped interior decorated with tempera frescoes on the central ceiling painted by the Italian artist Mauricio Ramelli, which represent scenes from the Divine Comedy and allegories of the muses of art. The theater was renamed in honor of the playwright Enrique Buenaventura, founder of the Cali Experimental Theater (TEC) and father of modern theater in Colombia. Located on Carrera 5 and Calle 7, in the heart of the historic center, the building stands on colonial stone foundations and borders the old Convent of the Company of Jesus. Its acoustics are considered perfect, attracting the most important opera, ballet and theater companies in the world, as well as the galas of the Cali International Theater Festival. Its surroundings invite you to take a walk through narrow streets full of colonial history, literary cafes and the constant memory of the era.', importancia_en = 'It is the most prestigious and oldest cultural scene in the city in operation.', datos_historicos_en = 'Inaugurated in 1927. It was renamed in honor of the great Cali playwright Enrique Buenaventura, father of the New Colombian Theater.', datos_curiosos_en = ARRAY['The mouth curtain was painted by the Italian artist Ricardo Richinimy and is a work of art in itself.', 'It has capacity for more than 1,000 spectators in its various locations.']::text[] WHERE id = 's2';

UPDATE sites SET nombre_en = 'Calima Theater', tipo_en = 'Theater', descripcion_en = 'The Calima Theater is a magnificent survivor of the golden age of great cinemas in the mid-20th century. Its modernist architecture, characterized by clean lines and large spaces, together with its enormous capacity, make it unique in the city. After a careful restoration that restored it to its original splendor, it has once again been a cultural epicenter, hosting everything from symphonic concerts to stand-up comedy shows. Its spacious lobby and façade are unmistakable on Sixth Avenue.', importancia_en = 'It is one of the most important Assets of Cultural Interest in the north of Cali and a benchmark of modern architecture.', datos_historicos_en = 'Opened in 1963, it was for decades the most elegant and technological cinema in the city.', datos_curiosos_en = ARRAY['It is one of the theaters with the largest capacity in the city (more than 1,200 seats).', 'It preserves the retro style of the 60s, including its typography and finishes.']::text[] WHERE id = 's41';

UPDATE sites SET nombre_en = 'Theater Store', tipo_en = 'Experimental Theater', descripcion_en = 'An intimate, warm and welcoming space in the San Antonio neighborhood, designed specifically for small format or ''chamber'' theater. The closeness with the actors is such that you can feel their breathing and see every gesture. He specializes in minimalist productions, acting training workshops and dramatic readings. It is the perfect place to discover new local talent and enjoy a quiet artistic evening with a good coffee.', importancia_en = 'Vital platform for the circulation of small format works, monologues and experimentation.', datos_historicos_en = 'Created by local artists with the need to decentralize the theatrical offer.', datos_curiosos_en = ARRAY['It also functions as a real ''store'' for artistic services and books.', 'The local café is a frequent meeting point for actors and directors.']::text[] WHERE id = 's44';

UPDATE sites SET nombre_en = 'Latin Corner Theater', tipo_en = 'Community Theater', descripcion_en = 'In 1973, a group of students from different majors at the Universidad del Valle began to meet in their free time to do what they were most passionate about: acting. In a Cali that only had TEC, that university "patch" led by Orlando Cajamarca became Esquina Latina, today one of the most important theater organizations in southwestern Colombia, with more than fifty years of artistic stubbornness. 

But what distinguishes Esquina Latina is not only its theater in the Tejares neighborhood of San Fernando: it is its conviction that theater is not for the elites. Through the "Youth, Theater and Community" program, active since 1987, it has brought theater to the communes of the east and the hillside of Cali and to municipalities hit by the conflict, training theater entertainers and using the stage as a tool of peace. Here the word "cultural" recovers its social meaning.', importancia_en = 'Reference for independent and community theater in the southwest; Historical Room recognized by the Ministry of Culture and Place of Memory of the city.', datos_historicos_en = 'It emerged in 1973 as a student group at the Universidad del Valle, led by Orlando Cajamarca; It was established as an autonomous non-profit entity between 1977 and 1978. It has had its own headquarters and hall since 1980. In 2023 it was recognized as a "Place of Memory" by the National Center for Historical Memory.', datos_curiosos_en = ARRAY['Its "Youth, Theater and Community" program has been working since 1987 in vulnerable communes and municipalities of the Valley and northern Cauca.', 'Thousands of people from popular sectors have gone on stage for the first time thanks to their Popular Theater Network.', 'Its founding director, Orlando Cajamarca, is a doctor, playwright and nationally and internationally awarded director.']::text[] WHERE id = 's42';

UPDATE sites SET nombre_en = 'Salamandra Theater', tipo_en = 'Cultural Center', descripcion_en = 'Located in the traditional San Fernando neighborhood, the Teatro Salamandra del Barco Ebrio is a true bastion of Cali cultural resistance. Founded and directed by the playwright Beatriz Monsalve, this space is not only a theater room, but a creation laboratory where independent cinema, literature, music and the performing arts converge. Its interior architecture, warm and clad in wood, evokes the hold of a ship where artistic dreams are born. It is home to the Cali International Theater Festival and a safe haven for critical thinking.', importancia_en = 'Epicenter of independent theater and organizer of international cultural events.', datos_historicos_en = 'The Barco Drunken Foundation was established in 1994, consolidating the Salamandra as its permanent headquarters.', datos_curiosos_en = ARRAY['Its full name pays homage to the poem ''The Drunken Ship'' by Arthur Rimbaud.', 'They have a very select film club programming and in-depth conversations.']::text[] WHERE id = 's66';

UPDATE sites SET nombre_en = 'Puppet House', tipo_en = 'Theater', descripcion_en = 'A magical and colorful world dedicated exclusively to the art of puppets and marionettes. Upon entering its doors, both children and adults enter a fantasy universe. It is the headquarters of the renowned ''Little Doll Theatre'' group and features an intimate theater room, a handmade toy shop and a wonderful permanent exhibition of puppets from around the world. It is the perfect family plan for the weekend, where imagination is the protagonist.', importancia_en = 'Main promoter of animation and object theater in western Colombia.', datos_historicos_en = 'Founded in 1998, they have kept the oral and visual tradition alive for decades, forming new generations of audiences.', datos_curiosos_en = ARRAY['They organize the ''Puppet Fair'' every year, bringing groups from all over the world.', 'The puppets you see on display have been used in historical works by the group.']::text[] WHERE id = 's67';

UPDATE sites SET nombre_en = 'Domus Theater', tipo_en = 'Theater', descripcion_en = 'A traditional house transformed into a vibrant setting. Domus Teatro is characterized by its familiar, welcoming atmosphere and its extreme closeness to the public. It is a space that is decisively committed to its own and contemporary dramaturgy, offering works that reflect on everyday life, humor and the human condition. Its interior patio and small café are ideal for chatting with the artists after the performance.', importancia_en = 'Vital space for the circulation of new theater groups and playwrights from Cali.', datos_historicos_en = 'It emerged as an independent initiative to decentralize theater and offer alternative spaces.', datos_curiosos_en = ARRAY['The stage is almost at the same level as the audience, breaking the ''fourth wall''.', 'They offer therapeutic theater workshops and for non-actors.']::text[] WHERE id = 's68';

UPDATE sites SET nombre_en = 'Cali Theatre', tipo_en = 'Theater', descripcion_en = 'Located in an imposing and beautiful mansion of Republican architecture in the foothills of San Antonio, Cali Teatro combines the elegance of the past with the vitality of modern theater. Directed by maestro Álvaro Arcos, it stands out for productions of the highest technical and aesthetic quality, ranging from universal classics to adaptations of Colombian literature. It is a space with a mystique and tradition unique to the city.', importancia_en = 'Undisputed benchmark of scenic quality and training of professional actors in the city.', datos_historicos_en = 'Founded in 1989, it occupies and preserves a heritage house from the late 19th century.', datos_curiosos_en = ARRAY['The room has a slope and acoustics specifically designed to project spoken voice without microphones.', 'Its dressing rooms keep stories and signatures of great national actors.']::text[] WHERE id = 's69';

UPDATE sites SET nombre_en = 'Omen Theater', tipo_en = 'Experimental Theater', descripcion_en = 'A true scenic laboratory located in the Granada neighborhood. The Omen Theater is known for its radical commitment to research and collective creation. His works usually mix various artistic languages, from the visual to the sound, constantly seeking new ways of narrating. It is a frequent venue for the Universidad del Valle for its thesis exhibitions, which guarantees freshness and avant-garde in its programming.', importancia_en = 'Fundamental bridge between experimental academic theater and the general public.', datos_historicos_en = 'The group was founded in 2000, consolidating its own room years later to have creative freedom.', datos_curiosos_en = ARRAY['They have a very popular children''s slot on Sunday mornings.', 'Its colorful and artistic façade is unmistakable on Avenida 9N.']::text[] WHERE id = 's70';

UPDATE sites SET nombre_en = 'TEC - Cali Experimental Theater', tipo_en = 'Experimental Theater', descripcion_en = 'Behind a brick facade and a metal door in the Santa Rosa neighborhood hides one of the most influential places in Latin American theater. The TEC was founded in 1955 by teacher Enrique Buenaventura together with students from the Departmental Institute of Fine Arts, and from there Colombia made one of its greatest contributions to the world scene: the method of “collective creation”, in which the actor is also the author and even the public is involved in the montage. 

Entering here is stepping into the place where Colombian theater became political, popular and experimental, with works that are still considered daring today. It is one of the few groups on the continent that keeps this line of joint creation alive, addressing social and human issues from a reflective and uncompromising perspective.', importancia_en = 'Cradle of the New Latin American Theater and collective creation; continental reference of performing arts committed to the social and political.', datos_historicos_en = 'Founded in 1955 by Enrique Buenaventura (1925–2003) and a group of Fine Arts students, initially linked to the Departmental School of Theater. Buenaventura—painter, poet, and playwright—developed and directed most of his works and theorized the method that other groups on the continent adopted.', datos_curiosos_en = ARRAY['Among his emblematic productions are The Papers of Hell, At the Right Hand of God the Father and The Complaint.', 'The method of collective creation is considered one of Colombia''s great contributions to the world history of theater.', 'The TEC has been in uninterrupted activity for more than 70 years: it is the oldest theater company in Colombia.']::text[] WHERE id = 's96';

UPDATE sites SET nombre_en = 'Monument to Sebastián de Belalcázar', tipo_en = 'Monument / Viewpoint', descripcion_en = 'On a hill to the west, the statue of the conquistador Sebastián de Belalcázar—founder of Cali in 1536—points with his right arm toward the Pacific. It was commissioned in the 1930s by the renowned Spanish sculptor Victorio Macho, made in Spain and brought by boat to Buenaventura and then on mule back to Cali; It was inaugurated in 1937, for the city''s 400th anniversary. For decades it was a classic viewpoint and one of the best panoramic views of Cali.\n\nBut the monument is also a disputed place today. In April 2021, during the National Strike, the Misak indigenous community tore it down, pointing out that the figure of Belalcázar represents the violence of the conquest. After a year and a half of debate, the statue returned to its pedestal in 2022, this time with a new plaque recognizing the role of the region''s indigenous people. The site is read in two keys at the same time: a viewpoint of the city and a memory in debate about how its founding is told.', importancia_en = 'Monument to the founder of the city and historical viewpoint; Today also a space for debate on the memory of the conquest.', datos_historicos_en = 'Bronze statue of the Spanish sculptor Victorio Macho, inaugurated on July 25, 1937 within the framework of the 400 years of Cali. On April 28, 2021, it was demolished by the Misak community during the National Strike, and reinstalled on November 4, 2022 with a new plaque that recognizes indigenous peoples.', datos_curiosos_en = ARRAY['The sculpture was made in Spain and arrived in Cali on muleback from Buenaventura.', 'Belalcázar appears pointing to the Pacific, with his left hand on his Tizona sword.', 'It offers one of the widest panoramic views of the city.']::text[] WHERE id = 's5';

UPDATE sites SET nombre_en = 'Christ the King', tipo_en = 'Monument', descripcion_en = 'With its arms open on the Cerro de los Cristales - named after the quartz that was abundant on its slopes - Christ the King watches over Cali from 1,440 meters high and from any corner of the city it is silhouetted against the green wall of the Farallones. Its 26 meters (21 of the image and 5 of the pedestal) and its 464 tons of iron and concrete were not born as a tourist attraction but as a symbol of peace: it was inaugurated on October 25, 1953 to commemorate the half century since the end of the Thousand Days War. 

Its construction has a story like a novel. The Jesuit José María Arteaga commissioned the work to Gerardo Navia from Palmyra, who only managed to make a model before abandoning it; The Italian Alideo Tazzioli, upon seeing it, responded that he did not fix other people''s works and proposed a new one. With calculations by his brother Adelindo, bamboo scaffolding and money collected by Father Arteaga and his boy scouts, the figure was raised in about four years. Going up today is a Cali rite as much as a pilgrimage: you go for the 360° view of the valley as well as for faith, and from 2024 the hill will be transformed into the Cristo Rey Integral Park, with new viewpoints and accesses.', importancia_en = 'Maximum icon of the Cali landscape and symbol of peace; viewpoint and pilgrimage point that receives hundreds of thousands of visitors a year. One of the most visited religious monuments in Colombia.', datos_historicos_en = 'Inaugurated on October 25, 1953 at the initiative of the Jesuit José María Arteaga, to commemorate the fifty years since the end of the Thousand Days War (1902). Sculpted by the Italian Alideo Tazzioli Fontanini, from Pietrasanta, after the abandonment of the project by its first author Gerardo Navia. Nearly 30,000 people attended his blessing.', datos_curiosos_en = ARRAY['It is the second tallest statue of Christ in Colombia, after Christ the King of Belalcázar.', 'It weighs 464 tons; Each of his arms alone weighs about 25.', 'Their scaffolding was made with guadua, the native bamboo of the region.', 'Along the ascent route, the artist Carlos Andrés Gómez has been sculpting geoglyphs on the ravines since 2011.']::text[] WHERE id = 's17';

UPDATE sites SET nombre_en = 'Loma de la Cruz', tipo_en = 'Crafts', descripcion_en = 'La Loma de la Cruz is the great artisan market of Cali and a point of popular open-air culture. It was born at the end of the eighties from an initiative of Artesanías de Colombia to give artisans a dignified and organized space; It was officially opened in 1990 and has been managed by the city since 1993. Around 120 artisan families work on its four levels and its theater, with pieces from all over the country and neighboring countries.\n\nIts name comes from the cross that crowns the hill, linked to old Cali legends - that of the slaves Crescencio and Juana, the "hand of the black" -, and to the cross that the Franciscans left there at the beginning of the 20th century. More than a market, it is a living cultural center: there is cinema, storytelling and poetry in the open air. A place where handmade work and popular memory go hand in hand.', importancia_en = 'Cali''s main craft center and popular culture space; meeting point for artisans of the country.', datos_historicos_en = 'The project began in 1987 at the initiative of Artesanías de Colombia (promoted by María Cristina Palau Londoño) and was officially inaugurated on July 12, 1990. In 1993 it passed to municipal administration.', datos_curiosos_en = ARRAY['It owes its name to the cross on the hill, shrouded in Cali legends from the 16th century.', 'It brings together around 120 artisan families on its four levels.', 'Its theater hosts films, stories and poetry recitals.']::text[] WHERE id = 's11';

UPDATE sites SET nombre_en = 'Cali Botanical Garden', tipo_en = 'Botanical garden', descripcion_en = 'In the middle basin of the Cali River, a stone''s throw from the Zoo, one of the last relics of the tropical dry forest survives—one of the most threatened ecosystems on the planet—turned into a garden. The project was born in 2001 from the efforts of biologist Jorge Enrique Orejuela and other people and institutions that set out to recover the river basin; The energy company EPSA gave on loan the hectares where samanes, guayacans and orchids grow today, one hundred species of butterflies flutter and more than one hundred birds nest. 

Since 2017, the Cali Zoological Foundation renovated it with a master plan that includes a four-story viewpoint designed by architect Simón Vélez, from where the forest canopy and the mountain range can be seen. It is a biodiversity refuge and outdoor classroom at the same time.', importancia_en = 'Tropical dry forest urban refuge and environmental education space; It connects the city with the natural heritage of the valley and helps regulate the basin from which Cali takes much of its water.', datos_historicos_en = 'Founded in 2001 by the Cali Botanical Garden Foundation, led by biologist Jorge Enrique Orejuela, on land donated by EPSA. In 2017 the Cali Zoological Foundation undertook its renovation; reopened to the renewed public in recent years.', datos_curiosos_en = ARRAY['It is home to more than 190 species of plants, a hundred butterflies and about 120 species of birds.', 'Its viewpoint-tower was designed by Simón Vélez, world master of guadua architecture.', 'The forest it protects helps regulate the basin from which Cali takes much of its water.']::text[] WHERE id = 's18';

UPDATE sites SET nombre_en = 'Pance River Ecopark', tipo_en = 'Natural Park', descripcion_en = 'Pance is the river of the soul of the people of Cali. The Ecopark, in the rural area in the south of the city, was born around 1970 when the Government of the Valley bought land to create a popular spa - the "Parque de la Salud" -, so that the Valle del Cauca tradition of bathing in the rivers would not be lost. The water comes down cold and crystalline from the Cali Farallones, where the river rises at about 4,000 meters above sea level.\n\nToday it is a weekend refuge: trails, bird watching, green areas, typical food restaurants and puddles to put your feet in. It is within a protected area, and that is why recreation coexists with the conservation of an ecosystem that supplies water to the city. Nature half an hour from the urban heat.', importancia_en = 'Main recreation space in nature for the people of Cali and symbol of the city''s link with its rivers.', datos_historicos_en = 'The Government of the Valley acquired the properties around 1970 to create the Popular and Recreational Spa of the Pance River. Since 1985 it has been administered by the Corporation for Popular Recreation, which consolidated the "Health Park".', datos_curiosos_en = ARRAY['The Pance River rises in the Farallones de Cali National Natural Park, at about 4,000 m above sea level. n. m.', 'On sunny weekends it can receive tens of thousands of visitors.', 'Its name comes from the Pance indigenous people, former inhabitants of the area.']::text[] WHERE id = 's20';

UPDATE sites SET nombre_en = 'San Antonio Chapel and neighborhood', tipo_en = 'public space', descripcion_en = 'Perched on its hill, the Chapel of San Antonio presides over the most bohemian neighborhood of Cali. The land was donated by Juan Francisco Garcés de Aguilar in his will of 1746, and the following year the chapel, dedicated to San Antonio de Padua, was already erected. It is simple and honest architecture—brick floor, white walls, brick façade with a semicircular arch—, related to the chapels of the Valley''s haciendas. From its atrium opens one of the most beloved views of the city.\n\nAround it grew one of the traditional neighborhoods of Cali, today a heritage landmark: steep streets, colorful houses, cafes, storytellers, restaurants and the sky full of kites in August. It is the place where the city goes to fall in love, hear stories and see the sunset. Heritage and daily life on the same hill.', importancia_en = 'One of the most emblematic colonial complexes and traditional neighborhoods of Cali; bohemian epicenter and National Monument.', datos_historicos_en = 'The chapel was erected in 1747, on land donated by Juan Francisco Garcés de Aguilar. The chapel and its hill were declared a National Monument in 1993, and the neighborhood recognized as an area of ​​heritage interest in 2000.', datos_curiosos_en = ARRAY['It is a traditional setting for storytellers and Cali bohemian culture.', 'In August, the hill is filled with people flying kites.', 'Its style refers to the chapels of the old haciendas of Valle del Cauca.']::text[] WHERE id = 's19';

UPDATE sites SET nombre_en = 'Pan American Park (Las Banderas)', tipo_en = 'public space', descripcion_en = 'A vast open space where the flags of the nations of America fly. Popularly known as the ''Parque de las Banderas'', it is the anteroom of the Pascual Guerrero Stadium. It is a massive meeting place, the scene of concerts, civic demonstrations and fairs. Its spaciousness allows you to feel the Cali breeze and observe the movement of 5th Street. It is a symbol of the city''s sporting vocation.', importancia_en = 'Built for the 1971 Pan American Games, an event that transformed Cali.', datos_historicos_en = 'It marked the beginning of the urban modernization of Cali towards the south.', datos_curiosos_en = ARRAY['It is the traditional meeting point to celebrate the triumphs of local soccer teams.', 'Under the flags there are fountains that refresh the atmosphere.']::text[] WHERE id = 's26';

UPDATE sites SET nombre_en = 'Heron Lake Ecopark', tipo_en = 'Natural Park', descripcion_en = 'A quiet and beautiful wetland in the south of the city, ideal for contemplation and silence. The park revolves around a lake surrounded by thick vegetation where, as its name indicates, herons, ducks, iguanas and turtles live. Its wooden and dirt paths allow for a relaxing walk in the shade. It is a perfect refuge for reading, meditating or walking with small children in direct contact with nature.', importancia_en = 'Key urban wetland for water regulation and wildlife refuge.', datos_historicos_en = 'Recovered by community and environmental management to avoid urbanization.', datos_curiosos_en = ARRAY['It is one of the best places for watching waterfowl within the city.', 'No music or loud noise is allowed to protect wildlife.']::text[] WHERE id = 's38';

UPDATE sites SET nombre_en = 'Cali Tower', tipo_en = 'Monument', descripcion_en = 'The skyscraper that defines the city''s urban profile. With 45 floors and 183 meters high, the Cali Tower is the tallest building in the city and one of the tallest in Colombia. Located on the banks of the Cali River in the Versalles neighborhood, it houses a luxury hotel and offices. Its silhouette is unmistakable and serves as a compass to orient yourself in the city. From its high floors, the view of the valley and the cliffs is breathtaking.', importancia_en = 'Landmark of modern architecture and symbol of Cali''s business development.', datos_historicos_en = 'Inaugurated in 1984, it was for years the tallest building in the country outside of Bogotá.', datos_curiosos_en = ARRAY['It has a ''Sky Bar'' on the 41st floor with panoramic night views.', 'Its construction marked the consolidation of the north as a financial area.']::text[] WHERE id = 's40';

UPDATE sites SET nombre_en = 'Music Park', tipo_en = 'public space', descripcion_en = 'A modern architectural complex in the north of Cali, designed specifically to celebrate the city''s musical vocation. With interactive water fountains, large squares and green spaces, it is ideal for outdoor events and urban relaxation. Its contemporary design contrasts with the surrounding industrial area, offering a cultural and recreational oasis near the Cali River.', importancia_en = 'Example of urban recovery of an old industrial area for cultural and recreational use.', datos_historicos_en = 'Built on the old grounds of an abandoned liquor factory.', datos_curiosos_en = ARRAY['It is often home to rock, hip hop and Pacific music festivals.', 'The fountains are illuminated at night, creating a visual spectacle.']::text[] WHERE id = 's47';

UPDATE sites SET nombre_en = 'Ingenuity Park', tipo_en = 'Natural/Cultural Park', descripcion_en = 'The largest and most beloved outdoor gym in Cali. This extensive linear park borders the Meléndez River and is the epicenter of sporting life in the south. From early morning until night, it is full of people jogging, cycling, doing yoga or enjoying their famous ''cholados'' and natural juices. Its large samanes trees offer perfect shade for family picnics.', importancia_en = 'Vital space for active recreation and public health of Cali residents.', datos_historicos_en = 'It arose from the donation of land from the old Meléndez sugar mill.', datos_curiosos_en = ARRAY['It is famous for its freshly squeezed orange and cane juice stands.', 'On weekends it is filled with families with pets.']::text[] WHERE id = 's48';

UPDATE sites SET nombre_en = 'Kilometer 18', tipo_en = 'Natural Park', descripcion_en = 'The ''fridge'' of Cali. Just 30 minutes from the city, up the road to the sea, the weather changes drastically to cold and foggy. Km 18 is the traditional plan to escape the heat, wear a ruana and drink aguapanela with hot cheese and corn arepa. In addition to gastronomy, it is a global paradise for bird watching, with unique species of hummingbirds and tanagers easily seen.', importancia_en = 'Area of ​​global importance for bird watching and gastronomic tourism.', datos_historicos_en = 'Historically it was the obligatory passage for muleteers between the Valley and the Pacific.', datos_curiosos_en = ARRAY['Here is the ''San Antonio Fog Forest'', a unique ecosystem.', 'It is famous for hot chocolate with cheese.']::text[] WHERE id = 's49';

UPDATE sites SET nombre_en = 'Airplane Park', tipo_en = 'public space', descripcion_en = 'An iconic park in the north of Cali where history lands. Its central attraction is a real airplane, a Douglas DC-6, installed in the middle of green areas and children''s games. It is a nostalgic place for many generations of Cali people who grew up playing under its wings. Recently renovated, it offers a safe space for family recreation and sports.', importancia_en = 'Urban landmark of the north of the city and historical curiosity.', datos_historicos_en = 'The plane arrived in the 90s and became a children''s library for a time.', datos_curiosos_en = ARRAY['It is a widely used geographical reference point: ''See you at the Airplane Park''.', 'The plane belonged to a commercial airline before being donated.']::text[] WHERE id = 's56';

UPDATE sites SET nombre_en = 'San Francisco Square', tipo_en = 'public space', descripcion_en = 'A wide red brick esplanade dominated by the imposing religious complex of San Francisco and the magnificent Mudejar Tower. It is a space of constant traffic, surrounded by government buildings such as the Government. Here you can feel the colonial history of Cali in dialogue with the modern administrative hustle and bustle. It is a mandatory photographic point for its unique architecture in Colombia.', importancia_en = 'It houses the Mudéjar Tower, considered the most valuable and unique architectural jewel of the city.', datos_historicos_en = 'The small square has been remodeled several times, historically serving as an atrium to the Franciscan temple.', datos_curiosos_en = ARRAY['Pigeons are permanent inhabitants of the square and tourists often feed them.', 'From here you have the best complete view of the Mudéjar Tower and its decorative bricks.']::text[] WHERE id = 's57';

UPDATE sites SET nombre_en = 'Poets Park', tipo_en = 'public space', descripcion_en = 'A literary corner in the middle of the center, near the La Ermita church. This park pays tribute to the great Valle del Cauca poets (Jorge Isaacs, Ricardo Nieto, Carlos Villafañe) with bronze sculptures that invite you to sit next to them. It is also the workplace of traditional ''scribes'', who with their typewriters write letters and legal documents, keeping alive an almost extinct trade.', importancia_en = 'Preservation of regional literary memory and the traditional profession of the scribe.', datos_historicos_en = 'Opened in 1995 to revitalize the urban space of the center.', datos_curiosos_en = ARRAY['You can ''chat'' and take photos sitting with the Jorge Isaacs statue.', 'The sound of typewriters is the park''s signature soundtrack.']::text[] WHERE id = 's58';

UPDATE sites SET nombre_en = 'Jovita monument', tipo_en = 'Monument', descripcion_en = 'Located in the emblematic Parque de los Estudiantes, right in front of the historic Colegio de Santa Librada (the oldest public educational institution in Cali, founded in 1823), the Jovita Monument pays tribute to Jovita Feijóo, the eternal queen of Cali friendliness. Sculpted in sheet iron by artist Diego Pombo, the more than four-meter-high structure captures its extravagant silhouette, crowned with multicolored flowers and feathers. Jovita was not from the aristocracy; She was a woman of the people who, in the mid-20th century, walked with distinguished steps along Fifth Street and the center of the city, wearing crowns and gala dresses made by herself. His figure represents the spirit of caleño: tolerance, the party as a space of resistance and the right to fantasy. Adjacent to the vibrant Carrera 15 and the Jovita Park sector, the monument is integrated into an area of ​​high bohemian and student effervescence. Walking through these blocks invites you to stop at the surrounding cultural cafes and contemplate how the statue is decorated daily with fresh flowers placed spontaneously by passersby, keeping alive the memory of the person who turned the street into his own royal palace.', importancia_en = 'Symbol of Cali popular culture and the acceptance of madness as part of identity.', datos_historicos_en = 'Jovita was named ''Queen of Sympathy'' in a massive public event in the 70s.', datos_curiosos_en = ARRAY['The statue always has fresh flowers left by the students.', 'It is the meeting point for student marches and carnival.']::text[] WHERE id = 's52';

UPDATE sites SET nombre_en = 'Ortiz Bridge', tipo_en = 'Monument', descripcion_en = 'More than a crossing over the river, the Ortiz Bridge is a witness to the history of Cali. Built of brick and lime, it was the first stable connection between the north and the center of the city. Today, perfectly integrated with Bulevar del Río, it is pedestrian and allows you to appreciate its original restored structure. It is a symbol of 19th century engineering and a romantic meeting point.', importancia_en = 'Asset of National Cultural Interest, vital for the urban development of Cali to the north.', datos_historicos_en = 'Built between 1842 and 1845 under the direction of Fray José Joaquín Escobar.', datos_curiosos_en = ARRAY['Thousands of eggs and bull blood were used in the original mixture to give it strength (according to oral tradition).', 'It was restored in 2011 revealing its original arches that were buried.']::text[] WHERE id = 's59';

UPDATE sites SET nombre_en = 'Rock Park', tipo_en = 'public space', descripcion_en = 'An elegant, fresh and tree-lined park in the heart of one of the most exclusive and bohemian neighborhoods in Cali. Surrounded by cafes, art galleries and signature restaurants, it is the perfect place to start a night of dinner or enjoy a quiet morning. On Sundays it transforms into a vibrant open-air gallery where local artists display and sell their paintings.', importancia_en = 'The most important informal artistic exhibition space in the city every Sunday.', datos_historicos_en = 'The El Peñón neighborhood was developed at the beginning of the 20th century as an upper-class residential area.', datos_curiosos_en = ARRAY['It houses a statue of Benito Juárez donated by Mexico.', 'It is known for its large trees that provide cool shade all day.']::text[] WHERE id = 's60';

UPDATE sites SET nombre_en = 'Cathedral of Saint Peter the Apostle', tipo_en = 'Iglesia', descripcion_en = 'Imposing and majestic, the Cathedral dominates the eastern side of the Plaza de Cayzedo. Its neoclassical style façade is a testimony to the faith and history of the city. Inside, its enormous crystal lamps, its tubular organ brought from Germany and its marble altars stand out. It is the headquarters of the Archdiocese of Cali and a place of silence and meditation in the midst of the bustle of the center.', importancia_en = 'Main Catholic temple of the city and Asset of Cultural Interest.', datos_historicos_en = 'The current construction dates back to the end of the 18th century, although it has undergone several renovations after earthquakes.', datos_curiosos_en = ARRAY['It keeps paintings from the Quito school of great value.', 'Its embossed bronze doors narrate biblical scenes.']::text[] WHERE id = 's64';

UPDATE sites SET nombre_en = 'Monument to Solidarity', tipo_en = 'Monument', descripcion_en = 'A monumental sculpture that captures the civic spirit of Cali. It represents a group of people of various races and conditions joining forces to build a structure, symbolizing that progress is achieved only in community and cooperation. Located on a northern roundabout, it is a powerful visual reminder of collective strength and mutual aid.', importancia_en = 'Symbol of civility and Cali unity.', datos_historicos_en = 'Inaugurated in 1995, work of the Cartagena sculptor Héctor Lombana.', datos_curiosos_en = ARRAY['It is made of bronze, slate and quartz.', 'It is one of the largest and heaviest monuments in the city.']::text[] WHERE id = 's76';

UPDATE sites SET nombre_en = 'Eastern Boulevard', tipo_en = 'public space', descripcion_en = 'A miracle of urban transformation in the Aguablanca District. What was once a stormwater channel and dividing land is today a vibrant 1.1 kilometer linear park filled with color, fields, games and art. It is the new pride of eastern Cali, a space of reconciliation where the community meets, plays sports and celebrates life. Its murals tell the neighborhood''s story of resistance and hope.', importancia_en = 'International model of how social urbanism can reduce violence and improve quality of life.', datos_historicos_en = 'Recently inaugurated as part of the ''5 Parks for Life'' project, transforming an invisible border area.', datos_curiosos_en = ARRAY['He has won international awards for architecture and urban design.', 'The neighbors themselves jealously take care of their gardens and equipment.']::text[] WHERE id = 's86';

UPDATE sites SET nombre_en = 'Alberto Galindo Sports Unit', tipo_en = 'Estadio', descripcion_en = 'A gigantic complex where sport meets culture. Here, the El Pueblo Coliseum (with its iconic ''spaceship'' style roof), the World Cup skating track, skate parks, climbing walls and large green areas coexist. But its magic explodes in August, when it becomes the citadel of the Petronio Álvarez Pacific Music Festival, filled with marimbas, viche and the best Afro-Colombian gastronomy.', importancia_en = 'Epicenter of major world sporting events and the largest Afro festival on the continent.', datos_historicos_en = 'Built for the 1971 Pan American Games, an event that modernized Cali.', datos_curiosos_en = ARRAY['The El Pueblo Coliseum is famous for its acoustics and futuristic design.', 'It is the favorite place for skaters and bikers in the city.']::text[] WHERE id = 's87';

UPDATE sites SET nombre_en = 'Tejada Cat Park', tipo_en = 'Sculpture', descripcion_en = 'On the banks of the Cali River, a three-ton bronze cat has become the city''s mascot. It is the work of the painter and sculptor Hernando Tejada, "Tejadita" (Pereira, 1924 – Cali, 1998), who donated it to Cali; was founded in Bogotá and inaugurated on July 3, 1996. With its more than three meters, its mischievous smile and its playful gesture, it broke with the solemnity of traditional monuments.\n\nTen years later, the Cat found company: "the cats of the river" were born, an open-air gallery of sculptures decorated by different artists -Ómar Rayo, Maripaz Jaramillo, Nadín Ospina, Jacanamijoy, among others—each one with its own style and personality. Today the Paseo del Gato is one of the most photographed corners of Cali: public art that people feel is theirs.', importancia_en = 'One of the popular symbols of Cali and point of an open-air sculpture gallery on the banks of the river.', datos_historicos_en = 'Bronze sculpture by Hernando Tejada, inaugurated on July 3, 1996 on the banks of the Cali River. In 2006, "the cat''s girlfriends/cats" were added, sculptures made by various artists, promoted by the Tejada family and the Chamber of Commerce.', datos_curiosos_en = ARRAY['It weighs around three tons and was cast in Bogotá.', 'Each of the "cats" was decorated by a different artist.', 'It is one of the most visited and photographed monuments in the city.']::text[] WHERE id = 's8';

UPDATE sites SET nombre_en = 'Cañaveralejo Arena', tipo_en = 'Event Center', descripcion_en = 'An iconic concrete structure that appears to float thanks to its cutting-edge engineering. Originally the city''s bullring, today it has been reinvented as the main entertainment center in southwestern Colombia. Its cup-shaped design allows perfect visibility from any angle. The largest concerts of the Cali Fair and international events are held here.', importancia_en = 'Jewel of Colombian engineering and National Monument for its bold structural design.', datos_historicos_en = 'Inaugurated in 1957. Its construction was a milestone for using innovative prefabricated elements for the time.', datos_curiosos_en = ARRAY['Its structure is anti-seismic and open, allowing wind circulation.', 'It is no longer used for bullfights, focusing entirely on culture and entertainment.']::text[] WHERE id = 's88';

UPDATE sites SET nombre_en = 'At Topa Tolondra', tipo_en = 'Live Music', descripcion_en = 'On the mythical Calle 5—the one that Grupo Niche names in "Cali Ají"—is the salsoteca where the music lover and the private dancer share the same dance floor. La Topa Tolondra opened in 2011 almost by chance: it started with a table and a refrigerator, and its name comes from the Valle del Cauca saying "a la topa tolondra", which is doing things on the run, without a plan. From that improvisation came one of the temples of the Cali rumba. 

It''s not just commercial salsa that sounds here: bugalú, pachanga, guaguancó, bolero and collectible Afro-Latin downloads play, with a music library that respects the roots of the genre. He teaches dance classes during the week and brings together people from Cali and foreigners around the dance floor. It is the place where it is understood that salsa here is not a show for tourists, but rather a daily occupation.', importancia_en = 'One of the contemporary temples of salsa in Cali; meeting point between the salsa tradition and the new generations.', datos_historicos_en = 'It opened its doors in 2011 as a small improvised bar and established itself as one of the city''s leading salsa bars.', datos_curiosos_en = ARRAY['It is on Calle 5, the same one that Grupo Niche mentions in "Cali Ají".', 'Many visitors take their first dance steps here, in classes prior to the party.', 'Their selection includes Los Hermanos Lebron, Ángel Canales and Sonora Ponceña.']::text[] WHERE id = 's7';

UPDATE sites SET nombre_en = 'Mulatto Cabaret', tipo_en = 'Salsa Show', descripcion_en = 'The first Latin cabaret in Colombia and an unmissable experience. Created by ''El Mulato'', this place offers a Broadway-style salsa show but with the Cali flavor and technique. It''s an immersive experience: the stage is everywhere and the dancers interact with the audience. The speed of the feet, the aerial acrobatics and the dazzling costumes make this show something unique in the world, showing the evolution of salsa.', importancia_en = 'He elevated Cali salsa to the category of world-class entertainment spectacle.', datos_historicos_en = 'Inaugurated after the global success of Swing Latino to have its own headquarters for permanent presentations.', datos_curiosos_en = ARRAY['After the show, the place turns into a nightclub for the audience to dance.', 'Jennifer Lopez has visited and praised this place and its dancers.']::text[] WHERE id = 's46';

UPDATE sites SET nombre_en = 'MalaMaña Salsa Bar', tipo_en = 'Live Music', descripcion_en = 'Located in a discreet basement in the San Antonio neighborhood, MalaMaña is the refuge of the salsa underground. It is dark, red, intense and authentic. Here only salsa brava, guaguancó and boogaloo sound, strictly in vinyl format. It is the favorite place for demanding dancers looking for space on the floor and good music without commercial interruptions or reggaeton. A hidden gem for purists.', importancia_en = 'Preserves vinyl culture and freestyle dancing in a countercultural environment.', datos_historicos_en = 'It was born as an alternative to crossover nightclubs, seeking to recover the essence of the neighborhood.', datos_curiosos_en = ARRAY['No songs are requested, you blindly trust the DJ''s selection.', 'Its discreet entrance means that only true connoisseurs arrive.']::text[] WHERE id = 's71';

UPDATE sites SET nombre_en = 'Point Baré', tipo_en = 'Live Music', descripcion_en = 'A club with a sophisticated air where Latin jazz and quality salsa meet. Punto Baré is famous for its excellent live music programming, offering a stage to the best local orchestras and jazz groups. The atmosphere is adult, comfortable and appreciative, with an excellent cocktail and wine list. It is the place to listen, feel and dance with elegance, far from the massive hustle and bustle.', importancia_en = 'Vital to the quality live music and jazz scene in Cali.', datos_historicos_en = 'Founded by music lovers who wanted a space with impeccable acoustics to listen to live.', datos_curiosos_en = ARRAY['It is common to see improvised ''jam sessions'' with visiting musicians.', 'Its name evokes the meeting point and the ''bar'' (baré).']::text[] WHERE id = 's72';

UPDATE sites SET nombre_en = 'The Devil''s Caldera', tipo_en = 'Live Music', descripcion_en = 'A corner with mystique and flavor on the emblematic Calle 5ta. La Caldera del Diablo lives up to its name: the atmosphere warms up with the best ''golpeada'' salsa and Antillean rhythms. Its decoration with masks, popular iconography and red lights creates a unique, almost ritual atmosphere. It is an unpretentious place where the only thing that matters is enjoying the music and hitting the tiles until dawn.', importancia_en = 'It keeps the essence of the neighborhood rumba alive in a tourist area.', datos_historicos_en = 'Inspired by popular Cali mythology about the devil and the eternal party.', datos_curiosos_en = ARRAY['They have cocktails with ''devilish'' and spicy names.', 'The music is curated for true salseros, avoiding commercial successes.']::text[] WHERE id = 's73';

UPDATE sites SET nombre_en = 'Star Latin Dance Academy', tipo_en = 'Salsa School', descripcion_en = 'In the heart of the Aguablanca District, Star Latin is much more than a dance academy; It is a life project for hundreds of young people. Here pure Cali style is forged at its finest: dizzying speed on the feet and challenging aerial acrobatics. To visit it is to see the raw talent, the overflowing passion and the iron discipline of those who dream of being world champions.', importancia_en = 'Social transformation and violence prevention through art and sports.', datos_historicos_en = 'Founded with the aim of giving life alternatives to young people in the sector.', datos_curiosos_en = ARRAY['Their rehearsals are open and the energy you feel is contagious.', 'They have represented Colombia in international competitions with great success.']::text[] WHERE id = 's84';

UPDATE sites SET nombre_en = 'Flavor and Swing Foundation', tipo_en = 'Salsa School', descripcion_en = 'A community school in the Comuneros II neighborhood that breathes passion and tradition. Sabor y Swing focuses on preserving the heritage of Cali dance while innovating high-impact group choreography. It is a humble space in infrastructure but full of human greatness, where children as young as 5 years old learn that salsa is discipline, teamwork and joy.', importancia_en = 'Vital social fabric in one of the most vulnerable areas of the city.', datos_historicos_en = 'It was born from the need to occupy the free time of the neighborhood children to keep them off the street.', datos_curiosos_en = ARRAY['Their competition costumes are often made by the dancers'' mothers.', 'They are frequent and award-winning protagonists of the Salsódromo.']::text[] WHERE id = 's85';

UPDATE sites SET nombre_en = 'Escuela de Baile King of the Swing', tipo_en = 'Salsa School', descripcion_en = 'Undisputed reference of the ''Caleño acrobatic'' style. King of the Swing is famous worldwide for the power, risk and height of its lifts and figures. Located in the east of the city, it is a factory of true dance athletes. Their choreographies are explosive and fast, reflecting the inexhaustible energy of their people. A place to admire human physical capacity to the rhythm of the clave.', importancia_en = 'Constant innovation in the acrobatic and sporting component of Cali salsa.', datos_historicos_en = 'They have trained dancers who today work in the most famous circuses and shows in the world.', datos_curiosos_en = ARRAY['They train with high-performance sports techniques.', 'The level of physical demand is comparable to that of Olympic gymnastics.']::text[] WHERE id = 's93';

UPDATE sites SET nombre_en = 'Alameda Market Square', tipo_en = 'Gastronomy', descripcion_en = 'More than a market, the Galería Alameda is a sanctuary of flavors and knowledge. Here the Pacific meets the Valley. It is the place where the most famous chefs in the city come to buy their fresh ingredients. Walking through its halls is a sensory feast: the smell of basil and cimarrón, the vibrant colors of exotic fruits such as lulo, chontaduro and borojó, and the sound of traditional cooks offering fish sancocho, ceviches, encocados and arroz atollado.', importancia_en = 'Main point of dissemination of the cuisine and culture of the Colombian Pacific in Cali.', datos_historicos_en = 'Founded in 1950, it has maintained its original open and airy architecture, typical of tropical markets.', datos_curiosos_en = ARRAY['Here you find the best ''spirits'' in the Pacific (Viche, Arrechón, Tumbacatre).', 'It is considered the best place to try the authentic ''rellena'' and the valluna chop.']::text[] WHERE id = 's9';

UPDATE sites SET nombre_en = 'Ringlete', tipo_en = 'Gastronomy', descripcion_en = 'The place where grandma''s kitchen dresses up. Ringlete has dedicated itself to researching and rescuing traditional Valle del Cauca recipes that were disappearing from the tables, serving them with an impeccable and modern presentation. The sancocho, the aborrajado, the marranitas and the arroz clavado taste here of history and home. Located in a cozy house in the Granada neighborhood, it is a mandatory stop to understand what Valle del Cauca really tastes like.', importancia_en = 'Rescue, research and elevation of local gastronomic heritage.', datos_historicos_en = 'Founded by chef Martha Jaramillo with the mission of dignifying Creole cuisine and its ingredients.', datos_curiosos_en = ARRAY['Their waiters are trained to explain the origin and ingredients of each dish.', 'The sweet figs with manjar blanco is legendary and is served in a traditional way.']::text[] WHERE id = 's31';

UPDATE sites SET nombre_en = 'The Rock', tipo_en = 'Gastronomic Zone', descripcion_en = 'El Peñón is one of the oldest and most stately neighborhoods in Cali, formed at the beginning of the 20th century on the banks of the river. It preserves a calm and artistic air that distinguishes it: traditional houses, antique shops, galleries, boutique hotels, cafes and restaurants. A few steps away are the La Tertulia Museum and the Gato del Río, which makes it a natural ending to a cultural day in the west of the city.\n\nIt is a neighborhood to walk without haste, where Cali''s residential past dialogues with an increasingly lively gastronomic scene. Art circuit, good food and urban memory, all next to the river.', importancia_en = 'Traditional neighborhood and cultural-gastronomic circuit next to the river; gateway to the western museum hub.', datos_historicos_en = 'One of the first neighborhoods in Cali, emerged at the beginning of the 20th century on the banks of the Cali River, historically linked to the residential and cultural development of the La Tertulia sector.', datos_curiosos_en = ARRAY['It is a traditional area of ​​antique shops and art galleries in the city.', 'Its proximity to La Tertulia and Gato del Río integrates it into the western cultural circuit.']::text[] WHERE id = 's37';

UPDATE sites SET nombre_en = 'Garden City', tipo_en = 'Gastronomic Zone', descripcion_en = 'The modern, green and expansive south of Cali. Ciudad Jardín is an oasis of wide avenues and lots of vegetation where the largest and most luxurious restaurants in the city are located. It is ideal for families and large groups due to the size of its premises and parking facilities. Here gastronomy mixes with open-air shopping centers and artificial lakes, offering an urban ''resort'' experience.', importancia_en = 'Development pole in the south of Cali, integrating nature, luxury housing and commerce.', datos_historicos_en = 'It was born as a country urbanization project in the 70s, seeking quality of life.', datos_curiosos_en = ARRAY['It is common to see guatines, squirrels and wild birds crossing the streets.', 'It concentrates the largest offer of high-end international cuisine in the city.']::text[] WHERE id = 's62';

UPDATE sites SET nombre_en = 'Cali Cultural Center', tipo_en = 'Cultural Center', descripcion_en = 'An impressive brick fortress dedicated to culture. Former headquarters of the FES, this building is a masterpiece of Colombian architecture, designed by the acclaimed Rogelio Salmona. Its interior patios, reflecting pools, ramps and the masterful use of brick invite exploration and calm. It houses the Ministry of Culture, a library, exhibition rooms and the valuable Historical Archive of Cali. It is a refuge of silence and beauty in the heart of the center.', importancia_en = 'Architectural landmark and administrative headquarters of municipal cultural management.', datos_historicos_en = 'Inaugurated in 1990. Its design reinterprets Islamic and pre-Columbian architecture.', datos_curiosos_en = ARRAY['It has a special acoustic: the sound of the water isolates you from the noise of the street.', 'From its terraces you have unique views of the city and the hills.']::text[] WHERE id = 's6';

UPDATE sites SET nombre_en = 'La Tertulia Cinematheque', tipo_en = 'Cine', descripcion_en = 'The sacred refuge of Cali movie buffs. This room, part of the La Tertulia Museum complex, is Cali''s window to world cinema that does not reach commercial theaters. Documentaries, European and Latin American cinema and restored classics are screened here with the best quality. Its intimate architecture and rigorously curated programming make it a place of worship for those who see cinema as art.', importancia_en = 'Vital space for the formation of audiences and the dissemination of Colombian and independent cinema.', datos_historicos_en = 'Founded in 1975, it has hosted international film festivals for decades.', datos_curiosos_en = ARRAY['It is the main venue of the Cali International Film Festival (FICCALI).', 'It offers outdoor performances in the museum gardens (''Cine al Río'').']::text[] WHERE id = 's45';

UPDATE sites SET nombre_en = 'Departmental Institute of Fine Arts', tipo_en = 'Universidad', descripcion_en = 'Bellas Artes is the silent factory behind much of Cali''s cultural scene: the first institution dedicated to the professional teaching of art in southwestern Colombia. It was born in the early 1930s at the initiative of maestro Antonio María Valencia – Cali pianist and composer – as a Music Conservatory, and from there it grew to embrace music, the plastic arts, design and the performing arts. 

Generations of musicians, painters, designers and actors who today represent the city have passed through its classrooms, and milestones such as the Cali International Art Festival have emerged from its midst. A heritage institution and engine of renewal at the same time, it is one of those places that are not seen on the tourist agenda but support, from below, everything else.', importancia_en = 'First professional artistic training school in southwestern Colombia; quarry of artists who have shaped Cali culture.', datos_historicos_en = 'Founded in the early 1930s (Cali Conservatory of Music, 1932–1933) on the initiative of maestro Antonio María Valencia. In 1936 it was departmentalized as the Cali Conservatory–Departmental School of Fine Arts.', datos_curiosos_en = ARRAY['The Cali International Art Festival arose from an idea by Fanny Mickey in the then "Palacio de Bellas Artes".', 'Its music conservatory is named after its founder, Antonio María Valencia.']::text[] WHERE id = 's32';

UPDATE sites SET nombre_en = 'Centennial Library', tipo_en = 'Library', descripcion_en = 'The elegant ''grandmother'' of Cali''s public libraries. Located near CAM and Fine Arts, it occupies a beautiful restored republican house that invites you to read. It is a quiet space full of charm, specialized in literature and cinema. Its ''La Pila'' screening room, its wooden shelves and its interior patio with a fountain are perfect to escape the noise of the center and immerse yourself in a good book.', importancia_en = 'First municipal public library of Cali and architectural heritage.', datos_historicos_en = 'Founded on July 20, 1910 to commemorate the centenary of Colombia''s independence.', datos_curiosos_en = ARRAY['It has a special collection (Railway Room) of Valle del Cauca authors.', 'His creative writing workshops ''La Pluma'' are very popular.']::text[] WHERE id = 's53';

UPDATE sites SET nombre_en = 'French Alliance', tipo_en = 'Cultural Center', descripcion_en = 'A little piece of France in the heart of Cali. Located in a renovated mansion in the Granada neighborhood, the Alliance is a dynamic center for European cultural dissemination. In addition to teaching French, it is famous for its media library, its French film series, philosophical debates and photography exhibitions. Its interior patio is the scene of the ''Music Festival'' every June, one of the most joyful and massive free events in the city.', importancia_en = 'Main promoter of French-speaking and European culture in the region.', datos_historicos_en = 'It has had an active presence in Cali for more than 50 years.', datos_curiosos_en = ARRAY['Their ''Crêpe France'' restaurant inside is delicious and authentic.', 'They bring exclusive French artists for their cultural events.']::text[] WHERE id = 's55';

UPDATE sites SET nombre_en = 'Columbus American Cultural Center', tipo_en = 'Cultural Center', descripcion_en = 'More than an English academy, the Colombo Americano is one of the most constant cultural engines of Cali: a binational center where the exchange between Colombia and the United States becomes concerts, exhibitions, cinema and reading. At its headquarters in the traditional Granada neighborhood, the Humberto Hernández art gallery coexists—which showcases artists from both countries, always with free admission—, the Earle Sherman Auditorium, the Abraham Lincoln bilingual library with more than 4,000 titles, and the IdeaLab Makerspace, a 3D printing, robotics and digital creation laboratory. 

Founded in 1954 as a non-profit foundation, it has grown to have several branches in the southwest and more than five thousand students, but its heart remains cultural and, to a large extent, free. It is one of those places where the word “cultural” does not adorn the name: the programming is real, sustained and open doors.', importancia_en = 'Pioneer and persevering: seven decades promoting jazz, blues and visual arts in Cali, and one of the few city centers with a continuous cultural agenda and free access.', datos_historicos_en = 'Founded in 1954 as a non-profit foundation and binational center recognized by the US Embassy. From its mother headquarters in Granada it grew to add offices in the south of Cali, Buga (1985) and Palmira (2005), with more than 5,000 students. In 2024 he turned 70 years old.', datos_curiosos_en = ARRAY['Its Cali Blues & Folk Festival (since 2006) won the international Keeping the Blues Alive Award from The Blues Foundation (Memphis) in 2020: it is the first and only Latin American festival to receive it.', 'In 2023, the Ministry of Culture recognized it among the 100 projects on the Biennial List of Projects of National Interest.', 'Its Abraham Lincoln bilingual library brings together more than 4,000 titles.', 'EducationUSA offers free advice to study in the United States.']::text[] WHERE id = 's54';

UPDATE sites SET nombre_en = 'Comuna 13 Cultural Entrepreneurship Center', tipo_en = 'Cultural Center', descripcion_en = 'An innovative and colorful space in the El Pondaje neighborhood, designed specifically to promote local talent and the orange economy. Here culture is seen as an engine of economic development. It has recording studios, dance rooms and workshops for creative entrepreneurs. It is the home of many hip hop, salsa choke and urban folk groups that are redefining the sound of Cali.', importancia_en = 'Incubator for creative economy and urban culture projects.', datos_historicos_en = 'Built to decentralize the cultural offer and support the professionalization of emerging artists.', datos_curiosos_en = ARRAY['Its geometric and colorful architecture stands out noticeably in its surroundings.', 'Offers marketing and management training for artists.']::text[] WHERE id = 's78';

UPDATE sites SET nombre_en = 'La Casona Didactic Center', tipo_en = 'Cultural Center', descripcion_en = 'A true educational and social oasis in the Marroquín II neighborhood. La Casona, operated by the Carvajal Foundation, is a historical benchmark of successful social intervention. More than a library, it is a community life center where children, youth and adults access books, systems courses, art, recreation and job training. Its environment is safe, green and welcoming, contrasting with the dense urban environment.', importancia_en = 'Pioneer in social and educational work in the Aguablanca District.', datos_historicos_en = 'It was one of the first quality social infrastructures to arrive in the area during its expansion.', datos_curiosos_en = ARRAY['It has a fantastic playroom that is very popular with children.', 'It is the heart of many neighborhood peace and coexistence initiatives.']::text[] WHERE id = 's79';

UPDATE sites SET nombre_en = 'Opening Doors Cultural Center', tipo_en = 'Cultural Center', descripcion_en = 'An inspiring initiative born from the community itself in the El Vallado neighborhood. ''Opening Doors'' is living proof that art saves lives. It is home to community theater, dance and music groups that work on issues of historical memory, violence prevention and coexistence. A humble space in resources but full of transformative force and local talent.', importancia_en = 'Brilliant example of community cultural self-management and resistance.', datos_historicos_en = 'Founded by community leaders to move young people away from invisible borders.', datos_curiosos_en = ARRAY['They use the ''Theater of the Oppressed'' as a work methodology.', 'Their works are presented in the streets of the neighborhood, integrating the public.']::text[] WHERE id = 's80';

UPDATE sites SET nombre_en = 'San Marino Public Library', tipo_en = 'Library', descripcion_en = 'Located in the heart of the San Marino neighborhood, this library is the safe haven for children and grandparents in the sector. It is a colorful, dynamic and active space where reading is mixed with craft workshops, film forums, digital literacy and story hours. His work in promoting reading in early childhood is notable and recognized.', importancia_en = 'Focus on culture, education and intergenerational meeting in Commune 7.', datos_historicos_en = 'Integral part of the Cali Public Library Network.', datos_curiosos_en = ARRAY['Their ''Storytelling Grandparents'' are famous and loved in the area.', 'They have a very nice collection of illustrated album books.']::text[] WHERE id = 's81';

UPDATE sites SET nombre_en = 'Daniel Guillard Public Library', tipo_en = 'Library', descripcion_en = 'Named after a Belgian priest who dedicated his life to serving the eastern community, this library in the Lagos neighborhood is a center of peace and learning. It offers a quiet and air-conditioned environment to study, free internet access and constant cultural programming. It is a key place and indispensable resource for students from nearby schools.', importancia_en = 'Honors social memory and community service through education.', datos_historicos_en = 'Father Daniel Guillard was a much loved social leader in the Aguablanca District.', datos_curiosos_en = ARRAY['They have a successful digital literacy program for older adults.', 'It is a safe and neutral meeting point for young people.']::text[] WHERE id = 's82';

UPDATE sites SET nombre_en = 'Los Naranjos Public Library', tipo_en = 'Library', descripcion_en = 'In the heart of Comuna 21, the Los Naranjos library is an engine of creativity and expression. It stands out for its strong link with the plastic and visual arts. Here books coexist harmoniously with exhibitions of painting, muralism and drawing workshops. It is a bright, airy and open space that invites you to imagine other possible worlds through art.', importancia_en = 'Active promoter of the visual arts and reading in the east of the city.', datos_historicos_en = 'It has established itself as the de facto cultural center of its neighborhood.', datos_curiosos_en = ARRAY['They create colorful community murals on their exterior walls.', 'They have a very active comic book and graphic novel reading club.']::text[] WHERE id = 's83';

UPDATE sites SET nombre_en = 'Isaías Duarte Cancino Public Library', tipo_en = 'Library', descripcion_en = 'Strategically located next to the hospital of the same name, this library understands culture as a form of healing and well-being. It has a unique focus on health, offering reading and support for patients and families, as well as workshops on healthy living. It is a refuge of calm, hope and constructive distraction in the midst of hospital activity.', importancia_en = 'Pioneer in linking reading and culture with public health.', datos_historicos_en = 'Named in memory of Monsignor Isaías Duarte Cancino, Archbishop of Cali and defender of human rights.', datos_curiosos_en = ARRAY['They carry carts with books (''Bibliocarritos'') to the hospital waiting rooms.', 'They organize very emotional reading aloud days.']::text[] WHERE id = 's89';

UPDATE sites SET nombre_en = 'Rigoberta Menchú Public Library', tipo_en = 'Library', descripcion_en = 'In the El Retiro neighborhood, this library proudly bears the name of the indigenous leader and Nobel Peace Prize winner. It is an active center of memory, diversity and human rights, with a special focus on Afro-Colombian and indigenous culture. Here roots are celebrated, identity is debated and bridges of peace are built through words and dialogue.', importancia_en = 'Defender of ethnic diversity and peace in Commune 15.', datos_historicos_en = 'Inaugurated with a strong message of social inclusion and respect for differences.', datos_curiosos_en = ARRAY['They have an excellent specialized collection of Afro-Colombian authors.', 'They celebrate African Heritage Month with great cultural events.']::text[] WHERE id = 's90';

UPDATE sites SET nombre_en = 'Desepaz Municipal Public Library', tipo_en = 'Library', descripcion_en = 'A cultural beacon in the far east of Cali. The Desepaz library is a fundamental infrastructure for the children and young people of Comuna 21. It offers large illuminated spaces for study, connected system rooms and an auditorium for events. It is known for its school reinforcement programs and for being a civic place where the community organizes and actively participates.', importancia_en = 'Vital point of access to information and technology in an area of ​​urban expansion.', datos_historicos_en = 'It was born together with the urban development of the Desepaz project (Development, Security and Peace).', datos_curiosos_en = ARRAY['It is one of the most visited libraries by high school students to do homework.', 'They have very talented youth dance and theater groups.']::text[] WHERE id = 's91';

UPDATE sites SET nombre_en = 'Andrés Sanín Library Station', tipo_en = 'Library', descripcion_en = 'Culture in motion. Strategically located within one of the busiest mass transit terminals (MIO), this library brings books directly to people''s steps. It is a small cultural oasis in the midst of the daily hustle and bustle, where travelers can read while they wait, borrow books for the road, or engage in quick reading. It shows that culture can be anywhere.', importancia_en = 'Democratization of access to books in unconventional and high-traffic spaces.', datos_historicos_en = 'Part of an innovative strategy of ''Library Stations'' integrated into the mass transportation system.', datos_curiosos_en = ARRAY['It operates a successful ''trust'' system for lending books.', 'It is small in space but has an incredibly high rotation of titles.']::text[] WHERE id = 's92';

UPDATE sites SET nombre_en = 'U.R El Vallado Cultural Center', tipo_en = 'Cultural Center', descripcion_en = 'A space for meeting and creation at the El Vallado Recreational Unit. This cultural center takes advantage of the sports and recreational infrastructure to offer a varied artistic program. It is a hybrid place where sport and culture go hand in hand: you can watch a folk dance rehearsal next to the soccer fields. Promotes the healthy use of free time and community integration.', importancia_en = 'Successful integration of sport, recreation and culture in a single community space.', datos_historicos_en = 'It arose to optimize the public spaces of the recreational unit.', datos_curiosos_en = ARRAY['On weekends it is the center of the neighborhood''s social life.', 'It hosts sports tournaments that include cultural components.']::text[] WHERE id = 's95';

UPDATE sites SET nombre_en = 'Cane Aquapark', tipo_en = 'Site of Interest / Water park', descripcion_en = 'The Acuaparque de la Caña is the large popular water park in Cali, and an institution of Cali recreation for more than four decades. It was born from a generous idea: to give families with fewer resources a spacious and decent place to cool off from the heat of the valley. Inaugurated in 1983 by then-president Belisario Betancur, it was the first park of its kind in southwestern Colombia, and its wave pool—the first in the region—became legend as soon as it opened.\n\nIts 156,000 square meters contain slides with storm names (Tornado, Extremo, Kamikazes), the tarzanera pool, lazy river, amusement rides, fields and stages for concerts. massive. It is managed by the Corporation for Popular Recreation, and hundreds of thousands of Cali residents have passed through its doors every year to visitors as illustrious as Pope John Paul II. More than a spa, it is a piece of the happy memory of several generations.', importancia_en = 'Main popular water park in southwestern Colombia and symbol of Cali recreation; the first of its kind in the region.', datos_historicos_en = 'It was inaugurated on July 3, 1983 by President Belisario Betancur, as a popular recreation project administered by the Corporation for Popular Recreation (created in 1979). Its wave pool was the first in the region.', datos_curiosos_en = ARRAY['Pope John Paul II visited it on July 3, 1986, on its third anniversary.', 'It occupies about 156,000 m² and receives about 700,000 visitors a year.', 'Its slides have names like Tornado, Extremo and Kamikazes.']::text[] WHERE id = 'new_1768272722685_455';

UPDATE sites SET nombre_en = 'Swing Latino', tipo_en = 'Salsa School', descripcion_en = 'The home of the undisputed world champions. Swing Latino is the school founded by ''El Mulato'', the visionary dancer who brought the dizzying Cali style to global stages (including the Super Bowl show with JLo). The training here is rigorous, athletic and passionate. It is the ideal place to watch professional-level rehearsals or take a class and understand the speed and acrobatics that characterize Cali dance.', importancia_en = 'Cultural ambassadors of Colombia to the world and creators of the Cali show style.', datos_historicos_en = 'Founded in the late 90s, it revolutionized the way of dancing salsa by integrating acrobatics and luxury costumes.', datos_curiosos_en = ARRAY['They have won the World Salsa Summit multiple times.', 'Many of its dancers come from popular neighborhoods, transforming their lives through dance.']::text[] WHERE id = 's27';

UPDATE sites SET nombre_en = 'Empire Youth Dance Academy', tipo_en = 'Salsa School', descripcion_en = 'One of the most awarded and respected schools in Cali. Empire Youth combines elegance and classic style with modern speed. Its headquarters is a hive of constant activity where the champions of the World Salsa Festival are prepared. His style is polished, precise and spectacular. To visit his rehearsals is to understand why Cali holds the title of world capital of salsa.', importancia_en = 'Multiple world champions and references of technical and artistic quality.', datos_historicos_en = 'Founded by Jefferson Benjumea and Adriana Ávila, a legendary dance couple worldwide.', datos_curiosos_en = ARRAY['They have participated in international reality shows such as ''Q''Viva! The Chosen''.', 'They have groups of all ages, from children''s ''seedbeds'' to professional cast.']::text[] WHERE id = 's94';

UPDATE sites SET nombre_en = 'Cali Zoo', tipo_en = 'Theme Park', descripcion_en = 'The Cali Zoo, founded in 1969, is internationally recognized as one of the best and most modern zoos in Latin America, and the only one accredited in Colombia by the Association of Zoos and Aquariums (AZA). Located on the western edge of the city, within the Cali River canyon in the Santa Teresita sector, the park stands out for its focus on biodiversity conservation, environmental education and animal welfare. It covers more than 25 hectares of recreated tropical jungle where nearly 2,500 animals of more than 230 species live, mainly from Colombian and South American fauna, including jaguars, Andean condors, spectacled bears, giant otters and a rich variety of primates. The zoo features unique immersive habitats such as the freshwater aquarium, interactive butterfly house, and cloud forest exhibit. Its pedestrian route runs under a thick natural shade fed by the clean waters of the Cali River, offering an oasis of freshness and scientific learning in the heart of the urban area.', importancia_en = 'Continental leader in the breeding and preservation of threatened species.', datos_historicos_en = 'Founded in 1969. It has transformed the concept of the classic zoo into one of immersion and respect.', datos_curiosos_en = ARRAY['The Cali River runs through the zoo, creating a cool microclimate.', 'They have a successful giant otter breeding program.']::text[] WHERE id = 's13';

UPDATE sites SET nombre_en = 'Jairo Varela Square', tipo_en = 'Monument', descripcion_en = 'In front of the CAM, in the heart of the center, this small square turns Cali''s salsa memory into a public space. It is dedicated to Jairo Varela (1949-2012), the Chocoano musician founder and director of Grupo Niche, author of "Cali pachanguero", that unofficial anthem of the city. Instead of a traditional bust, his tribute is a sound sculpture: an eight-meter golden structure, the work of architect Freddy Pantoja, which forms the word "NICHE" with trumpets and trombones and through whose bells the group''s music really sounds.\n\nPeople approach, discover the name hidden in the instrument, get under it to listen and end up dancing a few steps before continuing on their way. Next to the sculpture is the museum dedicated to the master. It is the urban recognition that in Cali salsa is not just rumba: it is heritage and identity.', importancia_en = 'Urban tribute to Jairo Varela and Grupo Niche; recognition of salsa as heritage and identity of the city.', datos_historicos_en = 'Small square dedicated to Jairo Varela, in the center of Cali in front of the CAM. His sound sculpture "Niche", by architect Freddy Pantoja, won a public competition (with a jury that included the maestro''s daughter, Cristina Varela, and the writer Umberto Valverde) and was inaugurated in December 2015.', datos_curiosos_en = ARRAY['The sculpture, about 8 meters, forms the word "NICHE" with trumpets and trombones.', 'Music recorded by Grupo Niche itself plays through its bells.', 'Next to the square there is a museum dedicated to Jairo Varela.']::text[] WHERE id = 's21';

UPDATE sites SET nombre_en = 'Salsa Museum', tipo_en = 'Museo', descripcion_en = 'On a block of the traditional Obrero neighborhood—the cradle of Cali salsa—there is a house that keeps the sonorous memory of an entire city. It all started in 1968, when photographer Carlos Alfredo Molina, camera in hand, began to photograph fair nights and the great artists who passed through Cali. From that curious lens was born an archive of more than 40,000 photographs that today is, by all accounts, the oldest salsa museum in the world. 

There are no cold showcases here: there is a track covered in black and white, walls covered with faces—Marvin Santiago, Gilberto Santa Rosa, Sonora Ponceña—and three generations of the same family who inherited the trade like someone who inherits a last name. More than a collection, it is a living testimony that in Cali culture is not only heard: it is inherited.', importancia_en = 'The oldest salsa museum in the world and guardian of the genre''s photographic memory; heart of the neighborhood recognized as the cradle of Cali salsa.', datos_historicos_en = 'It was born in 1968 from the work of photographer Carlos Alfredo Molina, who began documenting Cali''s salsa scene. His legacy is kept alive by his son and grandson, three generations of the Molina family.', datos_curiosos_en = ARRAY['It houses more than 40,000 photographs of musicians, orchestras and dancers.', 'There are only a handful of museums like this in the world: the others are in New York and Puerto Rico, and this is the oldest.', 'It also offers dance classes and supports children and young people of the Obrero.']::text[] WHERE id = 's25';

UPDATE sites SET nombre_en = 'La Tertulia Museum', tipo_en = 'Museo', descripcion_en = 'The La Tertulia Museum, founded in 1956 and moved to its current iconic headquarters on the banks of the Cali River in 1968, is the main epicenter of the plastic and visual arts in the city. Designed by celebrated architect Manuel Lago, the complex stands out for its bold architecture of pebble stone columns and geometric roofs that pay homage to the river landscape. The museum houses one of the most important collections of graphic works on paper in Latin America, in addition to having the legendary Cinemateca La Tertulia, a refuge for independent cinema since the time of the ''Caliwood'' group. Its outdoor gardens, inhabited by iguanas and shaded by giant samanes, function as a public meeting park where artists, students and locals gather to enjoy the Cali breeze at sunset. Connecting the museum with San Antonio Hill through Bulevar del Río allows a pedestrian route full of urban murals, signature cafes and independent galleries that breathe the bohemian spirit of Cali.', importancia_en = 'It was the first modern art museum founded in Colombia and is vital for the preservation of works on paper and graphic art.', datos_historicos_en = 'Founded in 1956 by Maritza Uribe de Urdinola during the Rojas Pinilla dictatorship as a space for freedom of expression. Its current building was inaugurated in 1968.', datos_curiosos_en = ARRAY['His collection of works on paper is one of the most important in Latin America.', 'The Cinemateca is the only room in the city dedicated exclusively to art cinema.']::text[] WHERE id = 's1';

UPDATE sites SET nombre_en = 'Nuevo Latir Cultural Center Public Library', tipo_en = 'Cultural Center', descripcion_en = 'The Nuevo Latir Public Library and Cultural Center, inaugurated in 2011 as part of the city''s Megaworks plan, represents the largest and most significant cultural and educational infrastructure in eastern Cali (Aguablanca District). Designed by architect Yemail Arquitectura with an innovative bioclimatic approach, the structure has thermal chimneys and parasols that allow the interior to be kept cool naturally in the warm climate of the east of the city. The center functions as a hub for development and social inclusion, housing specialized reading rooms, play libraries, auditoriums and digital rooms that connect thousands of young people from communes 13, 14 and 15 with knowledge. In addition to being a library, it is the official headquarters of multiple community events of the Petronio Álvarez Pacific Music Festival and periodically hosts decentralized concerts by the Cali Philharmonic Orchestra. Its construction at the intersection of the Aguablanca Trunk and Carrera 28 turned a vacant lot into an architectural beacon of polished cement and openwork panels that invites the community to appropriate knowledge and art in a safe and exchange environment.', importancia_en = 'The largest and most important cultural infrastructure in eastern Cali.', datos_historicos_en = 'Inaugurated in 2011 as one of the city''s ''Mega Works'' to close social gaps.', datos_curiosos_en = ARRAY['Its bioclimatic design allows it to be cool without air conditioning.', 'It hosts major concerts by the Cali Philharmonic Orchestra.']::text[] WHERE id = 's77';

UPDATE sites SET nombre_en = 'Jorge Isaacs Theater', tipo_en = 'Theater', descripcion_en = 'In front of the Ortiz Bridge, next to La Ermita and the Parque de los Poetas, the Jorge Isaacs Theater gives the historic center an elegance from another era. It was born from a misfortune and an ambition: where the Teatro Salón Moderno once stood—consumed by a fire in 1928—the businessman Hermann S. Bohmer built a new theater and named it in honor of Jorge Isaacs, the author of María. It was inaugurated on December 26, 1931. 

In French neoclassical style with nods to Italian romanticism, decorated with Ionic capitals, a stained glass window of the city''s coat of arms and the effigy of the poet, it boasts one of the best acoustics in the country. After decades of abandonment, it was declared a National Monument and restored, and today it is once again home to concerts, opera and great shows.', importancia_en = 'Architectural jewel and National Monument; one of the rooms with the greatest heritage value and best acoustics in southwestern Colombia.', datos_historicos_en = 'Built between 1930 and 1931 at the initiative of Hermann S. Bohmer, on the land of the old Salón Moderno Theater. Inaugurated on December 26, 1931. Declared a National Monument on November 26, 1984 and acquired by the State in 1986, when its restoration began.', datos_curiosos_en = ARRAY['A fire in its early years led to the creation of the Cali volunteer fire department.', 'Its acoustic box is one of the largest in Latin America.', 'Its name honors the author of María, Colombia''s most famous romantic novel.']::text[] WHERE id = 's22';

UPDATE sites SET nombre_en = 'Hacienda El Paraiso', tipo_en = 'House Museum', descripcion_en = 'At the foot of the Central Mountain Range, in El Cerrito, this 19th century white house is a literary pilgrimage: here Jorge Isaacs set María, the crowning novel of Latin American romanticism, translated into more than thirty languages. The house—the “Sierra House” of the book—preserves the layout described in the novel: Efraín''s room with its vase of always fresh roses, María''s room, the study, the room where the family gathered to embroider and sing. 

Surrounded by water channels that prevented the passage of insects, with cool balconies, a rose garden and a view of the sugarcane plains and the giant samanes, the hacienda makes literature and territory merge. In front of it is the stone where, according to the novel, lovers sat, today witness of visitors who swear eternal love.', importancia_en = 'María Scenario and main Asset of Cultural Interest in Valle del Cauca; literary icon of Latin American romanticism and pilgrimage destination for readers and lovers from around the world.', datos_historicos_en = 'The house was built between 1816 and 1828 by Víctor Cabal, a rancher from Buga and former mayor of Cali. It passed into the hands of Jorge Enrique Isaacs, the poet''s father, where he lived part of his childhood. Acquired by the department of Valle in 1953 and restored by master Luis Alberto Acuña in 1954. Since 2001 it has been in charge of INCIVA.', datos_curiosos_en = ARRAY['Maria was published in 1867; In 2017 its 150 years were commemorated with the Jorge Isaacs Year.', 'In Efraín''s room, fresh roses are renewed every day, in memory of the ones María brought him.', 'Jorge Isaacs was the face of the old 50,000 Colombian peso bill.']::text[] WHERE id = 's36';

UPDATE sites SET nombre_en = 'The Lantern', tipo_en = 'Craft Workshop', descripcion_en = 'Squeezed between the colorful houses of San Antonio is a printing press that refuses to die. The Lantern has been operating since 1934, printing street posters with movable type and linoleum engraving—the same technique with which Gutenberg changed the world half a millennium ago—on machines that are living relics: a Marinoni press from Paris (1870), a Reliance from New York (1890), a Rápida di Lusso from Turin (1934). For decades his posters covered the walls of Cali announcing concerts, plays and political campaigns. 

Andrés Caicedo was a client and friend of the workshop. In 2016 it almost closed. But in 2017 a group of managers and graphic artists reactivated it, articulating the centuries-old craft with contemporary design, and today it is a living cultural company, gallery and emblem of popular Cali graphics, with exhibitions in Mexico, Italy, France and Germany.', importancia_en = 'One of the last mobile typography workshops in Latin America and emblem of popular Colombian graphics; living heritage of the printed craft.', datos_historicos_en = 'Founded in 1934, it began printing in the Santa Rosa neighborhood and around 1987 it moved to San Antonio, its headquarters until today. After a crisis that almost closed it in 2016, it was reborn in 2017 as an intergenerational workshop-gallery, led by teachers Olmedo Franco, Jaime García and Héctor Otálvaro.', datos_curiosos_en = ARRAY['Editorial Planeta chose her to illustrate the covers of the reissues of Andrés Caicedo, a historical client of the workshop.', 'His machines are relics: a Marinoni press from Paris from 1870, a Reliance from New York from 1890, and a Rápida di Lusso from Turin from 1934.', 'His posters have already gone around the world in exhibitions in Europe and America.']::text[] WHERE id = 's43';

UPDATE sites SET nombre_en = 'Jorge Garcés Borrero Departmental Library', tipo_en = 'Library', descripcion_en = 'More than a book depository, the Departmental is a cultural plaza: the first departmental library in Colombia, born from a gesture of filial love. When the industrialist Jorge Garcés Borrero died in 1949, he left more than seven thousand books; His son Diego Garcés Giraldo, being governor of the Valley, donated them to found a public library in 1953 that would bear his father''s name. Convinced that "the progress of a society is made through education", he promoted it obsessively. 

After several offices, since 1990 it has occupied a 15,000 m² building next to Roosevelt Avenue, today the heart of the "Manzana del Saber". There are reading rooms with exhibitions, cinema, concerts, a valuable newspaper library and festivals such as "Hey, Look, Read". It embodies the idea that public culture has to be free and open doors.', importancia_en = 'First departmental library in Colombia and one of the most active cultural spaces in the southwest; Asset of Cultural Interest.', datos_historicos_en = 'Created in 1953 by decree of Governor Diego Garcés Giraldo and inaugurated on June 13, 1954, from the personal library of Jorge Garcés Borrero. Its current headquarters, measuring 15,000 m², was completed in 1990.', datos_curiosos_en = ARRAY['He was born with the ~7,000 books from the Garcés family''s personal library.', 'Every September it hosts the International Literature Festival "Hey, Look, Read".', 'Its newspaper archive preserves newspapers and magazines of great regional historical value.']::text[] WHERE id = 's15';

UPDATE sites SET nombre_en = 'Zaperoco Bar', tipo_en = 'Live Music', descripcion_en = 'In 1993, a trio of salsa-loving friends opened a salsa club on Avenida 5 Norte that they called Zaperoco. Over the years it passed into the hands of the Levy Cote family, who turned it into a bastion where the old and the modern coexist, with vinyl, live orchestras and a vocation that goes beyond rumba: to be a platform for the new bands in the city. In its beginnings, groups such as Herencia de Timbiquí performed on its stage. 

Its hallmark is the "Descargas Zaperoco" Thursdays—created together with the writer and music lover Umberto Valverde, a loyal client of the house—, large gatherings of musicians with rotating directors where the salsa is felt in the body. It is one of those places where the Cali night shows its most authentic side.', importancia_en = 'Historic Salsoteca and Cali live salsa platform; hotbed of new orchestras in the city.', datos_historicos_en = 'Founded in 1993 by a trio of friends on Avenida 5 Norte; Years later the Levy Cote family took over its management and consolidated it as a temple of salsa.', datos_curiosos_en = ARRAY['His Thursday "Zaperoco Downloads" were born together with the writer Umberto Valverde.', 'Herencia de Timbiquí passed through its stage in its beginnings.', 'It keeps live salsa alive, increasingly rare in the city.']::text[] WHERE id = 's28';

UPDATE sites SET nombre_en = 'Tin Tin Deo', tipo_en = 'Live Music', descripcion_en = 'Classic among classics, Tin Tin Deo is one of the most respected temples of salsa in Cali: a place where the genre is listened to with the same devotion with which it is danced. Its name – taken from a Dizzy Gillespie song – already announces the cult level of its musical selection, and its track is a pilgrimage point for dancers from all over the world. 

With decades of experience, it has sustained a lifelong club atmosphere where the connoisseur and the fan coexist. It is a must-see stop for anyone who wants to understand why Cali is called the world capital of salsa, beyond the tourist spectacle.', importancia_en = 'Cult salsa club and historical reference of Cali salsa; emblematic scene of the city''s nightlife.', datos_historicos_en = 'Salsoteca with a long history in Cali, recognized as one of the "temples" of the genre. [verify year of foundation and exact address]', datos_curiosos_en = ARRAY['Its name comes from a composition by jazz trumpeter Dizzy Gillespie.', 'It is usually cited among the most emblematic salsotecas in the city.']::text[] WHERE id = 's29';

UPDATE sites SET nombre_en = 'We Are Pacific Cultural Technocenter', tipo_en = 'Community Cultural Center', descripcion_en = 'In Potrero Grande, in the heart of the Aguablanca District—one of the territories hardest hit by inequality and largely populated by families displaced from the Pacific by the armed conflict—the Tecnocentro turns culture and technology into concrete opportunity. It was born from the dream of Sister Alba Stella Barreto, from the Paz y Bien Foundation, who wanted a neutral space where children could meet without the fear of "invisible borders" to learn theater, dance, music, robotics, video editing, programming and plastic arts. 

The result of a public-private alliance (Alvaralice Foundation, Comfandi, the Mayor''s Office, the Icesi University, the Ministry of Culture), it opened its doors around 2013 and since then it has served thousands of children and young people a year. It has its own symphony orchestra, public library and a Computer Clubhouse. It is proof that Cali''s cultural offer is also built, strongly, in the east.', importancia_en = 'The largest space for culture, technology and coexistence in eastern Cali; model of social transformation through art in a territory marked by violence.', datos_historicos_en = 'The project was born around 2009 at the initiative of Sister Alba Stella Barreto (Peace and Good Foundation); Its construction began in 2010 and it was inaugurated around 2013, as a public-private alliance led together with the Alvaralice Foundation.', datos_curiosos_en = ARRAY['His symphony orchestra was formed with the Batuta Foundation; several of his young people received scholarships at the Conservatory of Fine Arts.', 'His Computer Clubhouse was articulated with MIT in Boston.', 'Every year he presents the show "Pescadores de Sueños" at the Municipal Theater.']::text[] WHERE id = 's33';

UPDATE sites SET nombre_en = 'Delirium', tipo_en = 'Salsa Show', descripcion_en = 'In 2006, when Cali still carried the memory of its hardest times, four women—Andrea Buenaventura, former director of the Cali Fair, along with Eleonora Barberena, Liliana Ocampo and Ángela María Gallo—set out a delirious equation: bringing the salsa of the neighborhoods to the European cabaret format, adding circus and live orchestra. They started with a small platform that today is embarrassing in photos; They ended up creating one of the biggest salsa shows in the world. 

Under the Delirio Tent, on the last Friday of each month, the speed of Cali salsa meets acrobats, its own orchestra and a stage performance that has toured more than twenty countries. Behind the brilliance is a foundation with a social purpose: it uses dance and music to transform the lives of young people from sectors affected by violence. It is Cali converted into a creative industry and pride.', importancia_en = 'First and largest salsa cabaret, circus and orchestra show in Colombia; ambassador of quality to the world and model of creative industry with social impact.', datos_historicos_en = 'Founded in May 2006 by four cultural managers from Cali, based on the Circus Tent for All. It is presented on the last Friday of each month and has been recognized as one of the best salsa shows in the world.', datos_curiosos_en = ARRAY['It has performed hundreds of performances in more than 20 countries and has been seen by more than half a million people.', 'Their music is performed live by the Boranda Orchestra; The circus is provided by the Circo Herencias company.', 'Its social program "Paso Firme" works with young people from training centers in vulnerable contexts.']::text[] WHERE id = 's97';

UPDATE sites SET nombre_en = 'Audioteca Municipal', tipo_en = 'Archive', descripcion_en = 'The Cali Municipal Audio Library, located in the Cali Cultural Center (former headquarters of the FES), is the temple of the sound memory of the Pacific region and salsa. It houses thousands of phonograph records: from 78 rpm vinyl records of early salsa orchestras to field recordings of traditional Pacific music made by ethnomusicologists in the 1960s. It offers individual listening booths and a constant schedule of auditions guided by local music lovers and musicologists. It is an intimate and silent space, ideal for researchers and enthusiasts who seek to trace first-hand the origins of the Cali rhythm, surrounded by the stately atmosphere of the republican building in the historic center.', importancia_en = 'Unique sound repository in Colombia that preserves irreplaceable recordings of Pacific music and classical Cali salsa, many of them made in natural environments that no longer exist as they were captured.', datos_historicos_en = 'The collection was started in the 1960s by researchers from the Universidad del Valle and the Departmental Library, who began recording Pacific communities before modernization affected their oral traditions. The FES (Foundation for Higher Education) financed the digitization of much of the archive in the 1990s.', datos_curiosos_en = ARRAY['It preserves unique recordings of Pacific funeral rituals made in the 1950s that do not exist in any other archive in the world.', 'The catalog includes the first commercial recording of a Cali salsa orchestra, from 1968.', 'Researchers from the Smithsonian Institution have collaborated with the Audio Library to digitize its collection of indigenous music.']::text[] WHERE id = 's102';

UPDATE sites SET nombre_en = 'San Antonio Drink Stands', tipo_en = 'Gastronomy', descripcion_en = 'The traditional open-air drink stands on San Antonio Hill are the epicenter of refreshing and popular Cali cuisine. Here they serve the famous caleña luladas (a drink of crushed lulo with lemon, ice and optional condensed milk), the shampoos valluno - a drink of pre-Hispanic tradition made with cracked corn, lulo, pineapple, orange leaves and cinnamon - and shaved ice with multiple tropical flavors. The stalls, decorated with flowers and colorful umbrellas, are run by women from families that have been on the hill for generations, and the ritual of going down to have a cold drink while watching the Cali sunset go by is one of the most authentic social experiences in the bohemian neighborhood of San Antonio.', importancia_en = 'The beverage stalls of San Antonio preserve recipes and techniques for preparing pre-Hispanic and Hispanic-American refreshing drinks that are part of the intangible gastronomic heritage of Cali and Valle del Cauca.', datos_historicos_en = 'Shampoos is a drink of pre-Hispanic origin that was adopted and modified during the Spanish colony. The Cali preparation with corn, lulo and panela was consolidated as a tradition at the end of the 19th century. The San Antonio Hill stalls have existed since at least the 1940s, when the neighborhood was the bohemian and artistic center of the city.', datos_curiosos_en = ARRAY['The Cali lulada is considered the gastronomic cultural heritage of Cali by the Colombian Ministry of Culture.', 'The shampoo is served hot or cold: on cold December mornings it is offered hot as a comforting drink.', 'The lulo or naranjilla grows only in temperate climates of the Colombian and Ecuadorian Andes.']::text[] WHERE id = 's103';

UPDATE sites SET nombre_en = 'Traditional Bakeries of the Center', tipo_en = 'Gastronomy', descripcion_en = 'The traditional bakeries in the historic center of Cali are culinary institutions that survive over time. In these historic establishments, with wooden shelves and steam-fogged display cases, authentic pandebono—made with sour cassava starch and costeño cheese—, hot cassava bread, cheese pandeyuca, and giant corn fritters are baked from 5 in the morning. It is an immutable tradition to have breakfast in these bakeries accompanied by boiled oatmeal with cinnamon or freshly brewed red coffee, while the regular customers - downtown workers, lawyers, politicians - exchange news of the day loudly, composing a small democratic agora in which bread unites the city.', importancia_en = 'Pandebono is the most representative traditional snack of Valle del Cauca and Cali. The downtown bakeries are the guardians of the authentic recipe, in the face of the proliferation of industrial versions that alter the original ingredients and techniques.', datos_historicos_en = 'Pandebono has its origins in the Afro-Colombian communities of the Pacific coast, who prepared corn and yucca buns. Its current version with cheese was perfected in Valle del Cauca at the end of the 19th century. The first bakeries in the center of Cali date back to the 1910s, when the city was experiencing the boom of the cotton and coffee trade.', datos_curiosos_en = ARRAY['An authentic pandebono should be consumed within the first 15 minutes after coming out of the oven to enjoy its ideal texture.', 'The sour cassava starch used for pandebono takes up to 15 days to prepare through a fermentation process.', 'There are more than 30 varieties of pandebono in Valle del Cauca, each subregion with its own family recipe.']::text[] WHERE id = 's104';

UPDATE sites SET nombre_en = 'Boulevard Walls', tipo_en = 'Urban Art', descripcion_en = 'The urban mural circuit on the retaining walls of the Cali River, along the Boulevard, constitutes an open-air public art gallery that narrates the social and cultural history of Cali. With interventions by Cali street artists and international guests—many selected through the Cali Urban Art Festival (FAUC)—the murals combine hyperrealistic portraits of local cultural icons, illustrations of fauna endemic to Valle del Cauca, and political slogans of the Cali social movement. Walking the circuit is a visual journey that goes from the Poets Park to the Cervecería Bridge, with each wall telling a different story about urban identity, the river as a symbolic border and the popular resilience of Cali.', importancia_en = 'The Bulevar mural circuit is the most visited art gallery in Cali and one of the most relevant public art projects in southwestern Colombia, converting the functional flood containment walls into a space for aesthetic and political reflection.', datos_historicos_en = 'The first interventions on the walls of the Cali River were carried out informally by graffiti collectives in the 90s. Starting in 2010, the Cali Mayor''s Office institutionalized the process through the FAUC (Cali Urban Art Festival), converting the interventions into official commissions from recognized artists.', datos_curiosos_en = ARRAY['The Bulevar mural circuit has more than 2 km of continuous length, making it one of the longest in Latin America.', 'Several murals portray endangered endemic species of the Cauca Valley such as the black-faced duck and the Andean condor.', 'During the FAUC Festival, artists from more than 20 countries simultaneously intervene on the city walls.']::text[] WHERE id = 's105';

UPDATE sites SET nombre_en = 'Brewery Bridge', tipo_en = 'Urban Art', descripcion_en = 'The Brewery Bridge takes its historical name from the ancient Bavaria—known in Cali as "The Brewery"—which operated for decades on the land surrounding the Cali River. This vehicular and pedestrian bridge, which connects the Granada and Versalles neighborhoods with the Bulevar del Río sector, has become a canvas of monumental urban art. Its columns, railings and retaining walls are intervened with large-format pieces that mix the style of Latin American muralism with European street art. It is a mandatory stop for cyclists and pedestrians who travel along the river''s art circuit, offering spectacular views of the Cali water sheet from its sides.', importancia_en = 'The bridge is a symbolic connector between colonial Cali and modern Cali, and its artistic intervention turned it into a visual landmark of the river''s pedestrian circuit, revitalizing foot traffic between areas of the city that were previously traveled only by vehicle.', datos_historicos_en = 'The Bavaria Brewery was founded in Cali in 1904 and was one of the first modern industries in the city. The factory''s original warehouses were demolished in the 1980s to make way for residential developments. The name of the bridge has remained a popular memory of that industrial presence.', datos_curiosos_en = ARRAY['From the bridge you can see the flight of the white herons that nest in the trees on the banks of the Cali River.', 'Bavaria Cali was the first company in Colombia to produce beer industrially and cold.', 'The largest mural on the bridge measures 45 meters and was painted in a single night by a collective of artists during FAUC 2019.']::text[] WHERE id = 's106';

UPDATE sites SET nombre_en = 'Siloam Murals (Lleras)', tipo_en = 'Urban Art', descripcion_en = 'The murals of the Lleras neighborhood on the Siloé hillside (Comuna 20) are one of the most powerful expressions of community art and collective memory in Cali. Through a neighborhood tourism project self-managed by young people from the sector, the baked brick facades of the houses on the steep hillside became canvases that tell stories of resistance, honor the neighborhood leaders, document the history of artisanal coal mining and celebrate the Afro and indigenous wealth of the families who built Siloé with their own hands. The tour of the murals is done in the company of young local guides who narrate in first person the history of the neighborhood, its struggles and its cultural transformation, turning the visit into an exercise in transformative social tourism.', importancia_en = 'The Siloam murals are a model of how art can transform the public narrative of historically stigmatized neighborhoods. The project has turned Siloé into an internationally recognized cultural tourism destination, generating direct income for families in the sector.', datos_historicos_en = 'Siloé was founded in the 1920s by mining families who extracted coal from the veins of Cali''s western slope. Until the 90s, it was considered one of the most dangerous neighborhoods in the city. Starting in 2010, the youth organization "Ladera Cultura Viva" began the transformation process through art, murals and community tourism.', datos_curiosos_en = ARRAY['From the highest points of the Siloé murals you have one of the most complete panoramic views of the city of Cali and the Cauca Valley.', 'Several of the murals were painted by young people who had never picked up a paintbrush before entering Ladera Cultura Viva''s art program.', 'The Siloé neighborhood had the first urban coal mine in Colombia, operated until the 1960s.']::text[] WHERE id = 's107';

UPDATE sites SET nombre_en = 'Otero Building', tipo_en = 'Architecture', descripcion_en = 'The Otero Building, inaugurated in 1926 on a corner of the Plaza de Cayzedo, is one of the most beautiful examples of republican architecture in Cali, declared a Site of Cultural Interest by the Ministry of Culture. Designed with the influence of French neoclassicism, the building has a three-level façade with ornamental plaster details - garlands, fluted pilasters and medallions -, large wooden windows and a ground floor arcade that still functions as a commercial space. In its golden age, between the 1930s and 1950s, it housed the Hotel Europa—the most luxurious in the city—along with river transport companies and international trading houses. Today it is a stone witness to the economic flourishing of Cali as a transit city between the interior of the country and the port of Buenaventura.', importancia_en = 'The Otero Building is one of the few republican buildings in the historic center of Cali that preserves its original volumetry intact. Its preservation is key to maintaining the coherence of the architectural landscape of the Plaza de Cayzedo, the founding heart of the city.', datos_historicos_en = 'The building was commissioned by the Otero family, one of the most influential commercial families in Cali at the beginning of the 20th century. Its construction coincided with the economic boom that the city experienced after the opening of the Panama Canal in 1914 and the arrival of the Pacific Railway in 1915, which connected Cali directly to the ocean.', datos_curiosos_en = ARRAY['The Hotel Europa, which occupied the building, hosted Gabriel García Márquez during one of his visits to Cali in the 1950s.', 'The plaster ornaments on the façade were made by Italian craftsmen brought specifically for the construction.', 'The Plaza de Cayzedo, where the building is located, is kilometer zero of Cali: all distances in the city are measured from there.']::text[] WHERE id = 's108';

UPDATE sites SET nombre_en = 'Piper Pepper Monument', tipo_en = 'Monument', descripcion_en = 'The Monument to Piper Pimienta, inaugurated in 2000 in the traditional Barrio Obrero, pays tribute to Edulfamid Molina Díaz "Piper Pimienta", the Cali singer with a stylized figure, elegant dance steps and a falsetto voice who immortalized the city''s salsa anthem: "Las Caleñas son como las Flores." The bronze sculpture—the work of master sculptor Diego Pombo—portrays him with the microphone raised, his shoulders back and his right hand extended inviting him to the dance floor, capturing the festive attitude and charisma that made him the most beloved singer of the Cali style. Surrounding it, the Barrio Obrero—with its vinyl shops, saddlery workshops, and tenement house architecture—offers the perfect cultural context to understand the popular origins of salsa in Cali.', importancia_en = 'Piper Pimienta was the first artist to record salsa with a specifically Cali vocal and dance style, distancing himself from the New York model. "Las Caleñas son como las Flores" became the identity anthem of the city, recognized throughout the world of salsa.', datos_historicos_en = 'Edulfamid Molina Díaz was born in Cali in 1948 and started in music as a dancer before becoming a singer. He recorded his first album in 1971 with the Roberto Castillo Orchestra. "Las Caleñas son como las Flores" was recorded in 1979 and became the most distributed Cali salsa single in history. He died in Cali in 2002.', datos_curiosos_en = ARRAY['"Las Caleñas son como las Flores" has been recorded by more than 40 different artists around the world, being one of the most covered salsa songs in history.', 'Piper Pimienta was known for his dance style: he moved his shoulders and feet independently, a characteristic feature of Cali dancing.', 'The sculpture was financed by the residents of the Barrio Obrero through a popular collection.']::text[] WHERE id = 's109';

UPDATE sites SET nombre_en = 'Afro-Colombian Plaza', tipo_en = 'Plaza', descripcion_en = 'The Plaza de la Afrocolombianidad is a civic public space created in 2001 to honor and make visible the fundamental contribution of black communities to the social, cultural and economic development of Santiago de Cali. Cali is home to the largest Afro-descendant population of a city in Colombia—more than 500,000 people—and this plaza is its symbol of recognition in the heart of the city. The space has commemorative plaques and busts of Afro-descendant leaders and intellectuals from southwestern Colombia, such as Benkos Biohó, Tránsito Chávez and Jorge Artel. During Afro-Colombian Week (May), the plaza is transformed into a vibrant setting for gastronomic displays of Pacific cuisine—arroz atollado, arroz con coco, encocado de camarón—, chonta and shawmía marimba auditions, and academic forums on the rights of black communities.', importancia_en = 'The plaza is the only public space in Cali dedicated specifically to honoring Afro-descendant heritage, in a city where more than 25% of the population has African roots. It is a symbol of the political and cultural recognition of black communities in the urban space.', datos_historicos_en = 'The square was inaugurated on May 21, 2001, coinciding with Afro-Colombian Day, established in Colombia by Law 725 of 2001. The location was chosen for its proximity to the old neighborhood of El Calvario, one of the first neighborhoods to settle black communities arriving from the Pacific in the center of Cali.', datos_curiosos_en = ARRAY['Cali has the largest concentration of Afro-descendant population in South America in a single city, after Salvador de Bahia in Brazil.', 'The chonta marimba, the star instrument of Pacific music, was declared Intangible Heritage of Humanity by UNESCO in 2015.', 'Shrimp encocado and rice with coconut, Pacific dishes served in the plaza during festivals, have their origins in the kitchens of the Afro-Colombian communities on the coast.']::text[] WHERE id = 's110';

UPDATE sites SET nombre_en = 'Palace of the Government of the Valley', tipo_en = 'Governmental', descripcion_en = 'The San Francisco Palace, historical headquarters of the Government of Valle del Cauca, is an imposing architectural complex of international modernist style inaugurated in the 60s on the eastern side of the Plaza de San Francisco. The building stands out for its clean concrete volumes, its large blind walls and the large-format mosaic murals that adorn its main façade, the work of artist Pedro Nel Gómez, with allegories of the agrarian and industrial history of the department. The civic square that precedes it – the Plazoleta de San Francisco – is a space of great citizen activity: protests, official events, craft fairs and the constant pedestrian crossing that connects the historic center with the Bulevar del Río. In the immediate surroundings are the Church of San Francisco, the Convent of La Merced and the National Palace, forming the densest set of colonial and historical architecture in the center of Cali.', importancia_en = 'The San Francisco complex — which includes the Governor''s Office, the Church of San Francisco, the Plazoleta and the Convent of La Merced — is the core of Cali''s religious and civil architectural heritage, concentrating buildings from the 17th, 18th and 20th centuries in less than one block.', datos_historicos_en = 'The Convent of San Francisco, built in the same area in the 17th century, was the most important religious and educational institution in colonial Cali. In its patios the intellectual and political elites of the city were formed for almost three centuries. The current headquarters of the Government was built by demolishing part of the conventual facilities in the 60s.', datos_curiosos_en = ARRAY['The mosaic murals on the façade of the Government are the work of Pedro Nel Gómez, the same muralist of the Municipal Palace of Medellín.', 'The Church of San Francisco, next to the Governor''s Office, preserves one of the most beautiful baroque towers in all of Colombia, declared a National Monument.', 'In the small square of San Francisco, craft fairs are held every week where you can find products from the Nasa and Misak indigenous communities of Cauca.']::text[] WHERE id = 's111';

UPDATE sites SET nombre_en = 'Comedy House', tipo_en = 'Theater', descripcion_en = 'Casa Comedia is the most important theater space in Colombia dedicated exclusively to humor and the comic arts. Located in a cozy venue in the south of Cali, in the Ciudad Jardín neighborhood, it has an intimate room with 150 seats, a stage of perfect proportions and a weekly program that includes stand-up comedy, theater of the absurd, clown, mime and musical comedy. Recognized by the Ministry of Culture as a concerted theater venue, Casa Comedia is the springboard for the best emerging Colombian comedians and has presented international figures of humor in Spanish as guests. Its small, open-access café-bar invites conversation and socialization before and after performances, generating a loyal community of regular spectators around the transformative power of laughter.', importancia_en = 'Casa Comedia is the only concert hall specialized in humor in southwestern Colombia and one of the few spaces in the country where humor is treated with the same artistic seriousness as dramatic theater or dance.', datos_historicos_en = 'The room was founded in 2005 by the Cali actor and director Tato Torres, who dedicated his career to dignifying humor as a full artistic expression. In 2012 it was recognized by the Ministry of Culture as a Concerted Theater Hall, obtaining stable public financing for the first time in its history.', datos_curiosos_en = ARRAY['Casa Comedia has been the first stage for more than 30 Colombian comedians who today have national and international projection.', '"Open Mic" Fridays are completely free and anyone can come up on stage to tell their jokes for 5 minutes.', 'The theater has a "guaranteed laughter" policy: if the viewer does not laugh at any time, the ticket is returned.']::text[] WHERE id = 's112';

UPDATE sites SET nombre_en = 'Cali Historical Archive', tipo_en = 'Archive', descripcion_en = 'The Cali Historical Archive, located in the Cali Cultural Center (former headquarters of the FES), protects the oldest and most important documentary treasures of the city and the Cauca Valley. Its collection ranges from 16th century folios from the time of the Spanish Conquest to 20th century documents, including original council minutes, colonial wills, historical plans of the urban development of Cali, chronicles of the chroniclers of the Indies and correspondence of the heroes of the Independence of southwestern Colombia. The archive''s consultation room is open to historians, researchers, genealogists and citizens who wish to trace the history of their family, the neighborhood where they live or the country in general. Temporary documentary exhibitions make pieces that normally remain in conservation boxes accessible to the general public.', importancia_en = 'The Historical Archive of Cali is the oldest and most complete repository of the written memory of the city that exists. Without this archive, the history of Cali and Valle del Cauca would be largely unrecoverable. Its funds are an indispensable primary source for historical, legal and genealogical research throughout the region.', datos_historicos_en = 'The oldest documents in the archive date from 1536—just 20 years after the founding of Cali by Sebastián de Belalcázar. In its deposits are the founding documents of the city, the first baptism books of the Cathedral of San Pedro and the records of the first encomiendas granted to the conquerors in the Valle del Cauca.', datos_curiosos_en = ARRAY['The oldest document in the archive is a notarial act from 1536, written just 9 years after the founding of Cali.', 'In the archive you can find the birth and baptism certificates of historical figures from southwestern Colombia from the 18th century.', 'The process of digitizing the archive, begun in 2010, has made it possible to consult more than 500,000 historical folios online.']::text[] WHERE id = 's113';

UPDATE sites SET nombre_en = 'Ladera Museums', tipo_en = 'Community', descripcion_en = 'The Hillside Museums are a pioneering project of community and self-managed museology that brings together several memory centers located in the neighborhoods of the western slope of Cali (Comunas 18, 19 and 20). These spaces, installed in neighborhood houses and converted workshops, rescue the history of the migrant and displaced families who self-built these sectors since the 1940s, the memory of artisanal coal and lime mining, the Afro and indigenous oral traditions of the settlers, and the history of the social and organizational struggles of the hillside. Through historical photographs donated by neighbors, everyday objects, talking maps and oral stories, the museums offer an intimate and dignified perspective of the popular history of Cali that does not appear in official books.', importancia_en = 'The Ladera Museums are an internationally recognized model of how communities can appropriate their own historical memory without the intermediation of state institutions or universities. They have received visits from delegations of museologists from Argentina, Brazil and Spain who have adopted them as a reference.', datos_historicos_en = 'The first Ladera Museum was inaugurated in 2008 in the Siloé neighborhood, as part of a historical memory process led by the Ladera Cultura Viva Organization. The project expanded to other hillside neighborhoods between 2012 and 2018, with support from the Cali Mayor''s Office and the Ministry of Culture. Each museum has a neighborhood committee that decides which objects and stories are exhibited.', datos_curiosos_en = ARRAY['One of the museums displays more than 200 artisanal coal mining tools dating back to the 1940s, donated by mining families.', 'The museum guides are neighborhood residents who have received training in oral history and community museology.', 'The project was a finalist for the Ibero-American Intangible Heritage Award in 2019.']::text[] WHERE id = 's114';

UPDATE sites SET nombre_en = 'Pan American Courts', tipo_en = 'Deportivo', descripcion_en = 'The Jaime Aparicio Sports Unit—popularly known as the Pan-American Courts—is the sports and recreational heart of Cali, "Sports Capital of America." Built for the VII Pan American Games in 1971, this large complex of more than 40 hectares houses arenas for athletics, swimming, track cycling, tennis, basketball, boxing and soccer. The covered velodrome, the athletics track and the Olympic swimming pool are the most emblematic settings. In the afternoons and weekends, the complex is transformed into a massive civic meeting point where thousands of Cali people of all ages train, jog on the perimeter circuit, take dance classes in the sports centers and enjoy the gastronomic stalls of cholados, shampoos and fruit salads that surround the complex.', importancia_en = 'Cali is recognized as the "Sports Capital of America" ​​for having hosted the Pan American Games and for consistently producing world champions in disciplines such as cycling, boxing, weightlifting and athletics. The Pan American Courts are the physical epicenter of that sporting identity.', datos_historicos_en = 'The VII Pan American Games were held in Cali in August 1971, being the first to be held in a short Spanish-speaking city. 14 sports venues were built throughout the city. Olympic champions such as the cyclist Mauricio Soler and the boxer Antonio Cervantes "Kid Pambelé" got their start in these settings. In 2021 Cali hosted the Junior Pan American Games.', datos_curiosos_en = ARRAY['The Canchas Panamericanas velodrome is considered one of the three best in the world for track cycling, due to its banked curves and altitude conditions.', 'Cali has won more gold medals at the Pan American Games than any other Colombian city.', 'The 1971 Pan American Games were the first televised in color in all of Latin America.']::text[] WHERE id = 's115';

UPDATE sites SET nombre_en = 'Neighborhood Sports Centers', tipo_en = 'Deportivo', descripcion_en = 'The network of neighborhood sports centers in Cali represents the basic infrastructure of social inclusion and popular sports in the city. Distributed in all the urban communes of Cali, these spaces – equipped with multiple covered courts, skate parks, playgrounds and green areas – are the daily headquarters of the Mayor''s sports initiation schools for children and youth, the community micro-soccer tournaments and the dance and aerobics classes offered by the instructors of the Sports Secretariat. They are the social lungs of the popular neighborhoods of Cali: spaces where young people and families from all strata meet, compete and live together in an environment of sport, culture and peace, far from the dynamics of urban conflict.', importancia_en = 'Neighborhood sports centers are the most successful public sports and coexistence policy in Cali. Research from the Universidad del Valle has shown that in neighborhoods with active sports centers, rates of youth violence are up to 40% lower than in those without sports infrastructure.', datos_historicos_en = 'The neighborhood sports center program was initiated in Cali in the 1980s as part of the policy to recover public spaces and prevent youth violence. In the 2000s, under the municipal administration, the largest investment was made in neighborhood sports infrastructure in the history of the city, building or renovating more than 80 sports centers in all the communities.', datos_curiosos_en = ARRAY['Several world champions of boxing and cycling from Cali began their training in the neighborhood sports centers of their communities.', 'Saturday micro-soccer tournaments in sports centers attract up to 500 spectators and are the main social event in many popular neighborhoods of Cali.', 'Cali''s sports center network is the densest in Colombia: there is one for every 8,000 inhabitants on average.']::text[] WHERE id = 's116';

UPDATE sites SET nombre_en = 'Church of La Merced', tipo_en = 'Iglesia', descripcion_en = 'La Merced stands right where Cali was born: here, according to tradition, the founding mass of the city was celebrated in 1536. It is the oldest construction that survives in a city that erased almost all of its colonial architecture, and that is why it functions as a memory capsule: floors and altars in unpolished stone, a main altarpiece in red wood with gold leaf and the image of Our Lady of Mercy, patron saint of the city.\n\nMore than a temple, It is a complex that breathes history: next to the church, the convent of the Augustinian Recollects and the chapels of the Virgen de los Remedios - the "Montañerita Cimarrona", found in the western mountains around 1580 - and the Lateran Christ survive. It was the first property in Cali declared a National Monument. History upon history, like almost everything in this city.', importancia_en = 'The oldest construction in Cali and the symbolic place of its founding; first National Monument of the city and temple of its patron saint.', datos_historicos_en = 'The founding mass of Santiago de Cali was celebrated in its atrium in 1536. In February 1975 the convent complex received the official declaration as a National Monument, being the first property in the city with that recognition. It is in charge of the community of Augustinian Recollect Sisters.', datos_curiosos_en = ARRAY['The rosary that adorns the Virgin was a gift from Pope John Paul II during his visit to Cali in 1986.', 'The Virgin of Mercy received the baton of command from Joaquín de Caycedo y Cuero in 1811 and is considered, symbolically, governor of the city.', 'A host factory still operates in the complex that supplies parishes in the country.']::text[] WHERE id = 's_merced';

UPDATE sites SET nombre_en = 'Church of San Francisco and Mudejar Tower', tipo_en = 'Church/Heritage', descripcion_en = 'The San Francisco complex is a narrative in brick and faith. The Franciscans arrived in Cali around 1750 and built a complex that today includes the convent of San Joaquín, the Chapel of the Immaculate Conception, the imposing neoclassical church and—its jewel—the Mudéjar Tower. That tower of about 23 meters, built around 1772, with its brick bodies cut in trapezoids forming geometries with an oriental air, has been described by the historian Santiago Sebastián as "the most beautiful Mudejar tower in all of America".\n\nIt is the trace of the miscegenation that marked the city: in the tower you can breathe the Spanish-Muslim legacy that crossed the Atlantic, and in the church, the rational thought of the neoclassical. A legend attributes the design to an exiled "Moor", which adds mystery to a unique monument in Colombia. Around, the square and its pigeons do the rest.', importancia_en = 'Franciscan heritage complex and headquarters of the Mudéjar Tower, considered the most beautiful in America; symbol of the architectural fusion of Cali.', datos_historicos_en = 'The convent was built in 1757, with the Chapel of the Immaculate Conception completed around 1764. The Mudéjar Tower dates from around 1772. The current neoclassical church was built between 1803 and 1827, based on designs by the priest Andrés Marcelino Pérez de Arroyo. It was nominated for National Monument status in 1982.', datos_curiosos_en = ARRAY['The Mudéjar Tower is compared to the Giralda in Seville for its brick geometries.', 'The church survived the earthquakes of 1885, 1896 and 1925, preserving its appearance.', 'The adjacent plaza is flanked by the Valle Government building.']::text[] WHERE id = 's_sanfrancisco';

UPDATE sites SET nombre_en = 'La Ermita Church', tipo_en = 'Iglesia', descripcion_en = 'The neo-Gothic image of La Ermita, blue and white next to the river, is one of the most recognized postcards of Cali. But the church we see today is relatively young: the original hermitage, built at the beginning of the 17th century, was destroyed by the earthquake of June 7, 1925; Only the venerated image of the Lord of the Reed was saved from it. On these ruins, two Cali sisters - Micaela and Asunción Castro Borrero - promoted the construction of the current temple, inspired by the cathedral of Ulm, in Germany.\n\nCompleted in concrete and inaugurated in 1942, La Ermita is almost a catalog of the world brought to Cali: Carrara marble on its altars, bells cast in France, and a musical clock and stained glass windows with the twelve apostles commissioned in Amsterdam. A little piece of Europe on the riverbank, which survived where the city lost almost all of its ancient architecture.', importancia_en = 'Emblematic temple and one of the main architectural postcards of Cali; jewel of the neo-Gothic style in Colombia and Asset of Cultural Interest.', datos_historicos_en = 'The primitive hermitage, from the beginning of the 17th century, was destroyed by the earthquake of 1925. The current neo-Gothic temple, promoted by the Castro Borrero sisters and built under the direction of the engineer Pablo Emilio Páez, was inaugurated on April 21, 1942, dedicated to Our Lady of Sorrows.', datos_curiosos_en = ARRAY['Its design was inspired by the Ulm Cathedral (Germany).', 'The musical clock and the stained glass windows of the twelve apostles were brought from Amsterdam; the bells, from France.', 'The iron doors were manufactured in Cali in 1937.']::text[] WHERE id = 's16';

UPDATE sites SET nombre_en = 'Orquideorama', tipo_en = 'Museum/Garden', descripcion_en = 'The Orquideorama is a "living museum" in the north of Cali: a green haven dedicated to the flower that best represents Colombia, the most diverse country in the world for orchids. It has been managed for more than forty years by the Vallecaucana Association of Orchidology, and its architecture—with wide ceilings and wood—evokes the old sugar mills of Valle del Cauca, a nod to the landscape that surrounds it.\n\nHere native species are conserved, studied and exhibited in exhibitions that bring together nearly 180 types of orchids, in addition to a nursery and a collection of trees. It offers cultivation workshops, guided tours for schools and every year it hosts the international exhibition CaliOrquídeas. It is named after the botanist Enrique Pérez Arbeláez, and it is one of those discreet places where the city reconciles itself with its biodiversity.', importancia_en = 'Living orchid museum and conservation center for Valle del Cauca flora; headquarters of the Vallecaucana Association of Orchidology.', datos_historicos_en = 'The Vallecaucana Association of Orchidology obtained the land on loan from the Mayor''s Office in 1981, to celebrate the VII International Orchid Exhibition, and built its current headquarters there (designed by architect José Luis Giraldo). It is registered in the Valle del Cauca Museum Network.', datos_curiosos_en = ARRAY['Its architecture is reminiscent of the old sugar mills of the Valley.', 'Every year it holds the international exhibition CaliOrquídeas.', 'It is named after the eminent Colombian botanist Enrique Pérez Arbeláez.']::text[] WHERE id = 'new_1768272723371_563';

UPDATE sites SET nombre_en = 'The Star of Siloam', tipo_en = 'Site of Interest / Viewpoint', descripcion_en = 'At the top of commune 20, on the western slope, a star shines that is much more than a Christmas decoration: it is the symbol of Siloam and its people. It was born from a dream of Professor Alberto Marulanda Palacios, who in the early seventies looked at the hillside covered with small houses lit with candles and oil lamps and saw it as a natural manger that was only missing its star of Bethlehem. After years of community management, the first star—five-pointed and made of guadua—was lit on December 16, 1973 and became visible from the entire city.\n\nToday the star is a beacon and flag of a territory that for decades carried the stigma of violence and that its own young people are transforming into a cultural destination. The Popular Museum of Siloé and the Cooperativo La Estrella collective built the stairs and the viewpoint with their hands, and offer tours that tell the history of the neighborhood, its murals and its music. Climbing up to the star—now renewed—is seeing one of the best views of Cali and, above all, a lesson in resilience.', importancia_en = 'Icon of commune 20 and symbol of resistance and social transformation of Siloé; one of the great viewpoints of the city and axis of community tourism.', datos_historicos_en = 'Devised by Professor Alberto Marulanda Palacios, the star was lit for the first time on December 16, 1973, with the support of Emcali. Originally five-pointed, around 2007 it became a sixteen-pointed structure, and in 2025 it was restored to its original five-pointed design with 27,000 LED lights.', datos_curiosos_en = ARRAY['The illuminated hillside evoked a manger; hence the idea of ​​crowning it with a star.', 'The Siloé Popular Museum and the La Estrella Cooperative built the viewpoint and access stairs.', 'You can get there by MíoCable, getting off at the Lleras Camargo station.']::text[] WHERE id = 'new_1768272724018_46';

UPDATE sites SET nombre_en = 'Cañasgordas Club Recreational and Sports Center Comfenalco Valle Delagente', tipo_en = 'Recreation Center', descripcion_en = 'In the south of the city, in the countryside sector of the Lili Valley, the Cañasgordas Club is one of the large recreational centers of the Comfenalco Valle Delagente compensation fund: a space designed for rest and sports for the Valley''s working families. Among large green areas, it offers swimming pools with slides, fourteen clay tennis courts with night lighting, soccer fields with natural and synthetic grass, a restaurant and children''s areas.\n\nAs part of the compensation fund system - a very Colombian social welfare institution - it subsidizes the income of its members, and in recent years it has also opted to become an environmental lung, with rainwater harvesting and solar energy. It is popular recreation in a contemporary key.', importancia_en = 'Recreation and sports center of the Comfenalco Valle compensation fund; wellness space for working families in the south of the city.', datos_historicos_en = 'Managed by the Comfenalco Valle Delagente Family Compensation Fund, in recent years (since 2019) it has been the subject of an expansion plan with new fields, parking lots and sustainable water and energy systems.', datos_curiosos_en = ARRAY['It has fourteen clay tennis courts with lighting for night play.', 'It plans to become an environmental "lung" with rainwater collection and solar energy.', 'Members of categories A and B have access at a subsidized rate, sometimes free.']::text[] WHERE id = 'new_1768272721586_95';

UPDATE sites SET nombre_en = 'Comfandi Pance Country Center', tipo_en = 'Sports/Recreational Center', descripcion_en = 'On the way to Pance, at kilometer 17 of the Cali–Jamundí highway, the Comfandi Campestre Center is a large recreational park of the Comfandi compensation fund, surrounded by nature at the foot of the hills. It is a family day plan: swimming pools and water park, soccer and tennis courts, ecological trails, rowing and fishing lakes, gym and sports school, all among heavily wooded green areas where birds can also be seen.\n\nIt adds adventure attractions such as a 500-meter zip line between towers, and in December it is transformed with its Christmas park. Like the other compensation fund centers, it subsidizes the income of its members and offers programs such as "constructive vacations" for children. It is recreation with a country air, just a few minutes from the city.', importancia_en = 'Recreational and sports center of the Comfandi compensation fund in the natural environment of Pance; space for family recreation and sports training.', datos_historicos_en = 'Administered by the Family Compensation Fund of Valle del Cauca (Comfandi), it is part of its network of recreational centers in the department.', datos_curiosos_en = ARRAY['It has a zip line of about 500 meters between three towers.', 'Its lake is for contemplation and paddling only; Swimming is not allowed in it.', 'During the Christmas season, a Christmas park is set up for families.']::text[] WHERE id = 'new_1768272722278_963';

UPDATE sites SET nombre_en = 'Cayzedo Square', tipo_en = 'public space', descripcion_en = 'It is the historic heart of Cali and its meeting point par excellence. It was the colonial Plaza Mayor, then Plaza de la Constitución, and since 1913 it has been named after Joaquín de Cayzedo y Cuero, a hero of independence, whose bronze statue presides over the place under the tall royal palms. Around it rise the buildings that tell the history of power in the city: the National Palace, the stately Otero Building and the Cathedral of San Pedro, all national monuments.\n\nFor centuries it was a public market, then a park, and today it is the living room of the city: shoe shiners, retirees, pigeons, demonstrations and tourists share its benches. A place where you can take the pulse of Cali without needing anything else.', importancia_en = 'Main square and historic center of Cali; set of national monuments around its perimeter.', datos_historicos_en = 'The former colonial Plaza Mayor was renamed Plaza de Cayzedo in 1913 in honor of the hero Joaquín de Cayzedo y Cuero, whose statue was erected that same year. It functioned as a public market until the end of the 19th century and was remodeled in 1986, to mark the 450th anniversary of the city.', datos_curiosos_en = ARRAY['His royal palms are an inseparable part of his image.', 'It is surrounded by the National Palace, the Otero Building and the Cathedral of San Pedro.', 'It occupies nearly 6,500 square meters in the heart of the center.']::text[] WHERE id = 's39';

UPDATE sites SET nombre_en = 'Hill of the Three Crosses', tipo_en = 'Natural Park', descripcion_en = 'At 1,480 meters high, the Cerro de las Tres Cruces is the open-air gym and spiritual viewpoint of Cali. Every morning, especially on weekends, hundreds of Caleños climb its steep trails to exercise and reward themselves with a complete view of the city, the valley and the Farallones. It is a health rite and a postcard at the same time.\n\nIts three crosses have the origin of legend: it is said that in 1837 some Franciscan friars planted three guadua crosses to exorcise "Buziraco", a demon to whom they attributed the misfortunes of the city. The 1925 earthquake demolished them, and in their place the current concrete crosses were raised, around 1937. Faith, sport and landscape come together on the most Cali peak of all.', importancia_en = 'Tutelary hill and emblematic viewpoint of Cali; place of popular sport and religious tradition.', datos_historicos_en = 'According to tradition, in 1837 Franciscan friars placed three guadua crosses to conjure the legend of "Buziraco." The concrete crosses that today crown the hill were erected around 1937-1938, after the previous ones fell in the 1925 earthquake.', datos_curiosos_en = ARRAY['The central cross measures about 26 meters high.', 'Every May 3, Day of the Cross, and during Holy Week, pilgrimages are carried out.', 'It is one of the most popular sports climbs in the city.']::text[] WHERE id = 's65';

UPDATE sites SET nombre_en = 'River Boulevard', tipo_en = 'public space', descripcion_en = 'Bulevar del Río—or Colombia Avenue Bulevar—is Cali''s great pedestrian hall on the banks of the river. Before, cars used to pass through there; Today they circulate through an underground tunnel (the longest in Colombia in an urban area) while above people walk under the palms. Inaugurated in 2013 within the city''s "Megaworks", it became the largest public space in Cali, with thousands of people walking through it every day.\n\nIn less than a kilometer it connects a good part of the city''s memory: La Ermita, the Jorge Isaacs Theater, the Parque de los Poetas, the Ortiz Bridge and the Paseo Bolívar. With its steel towers, its restaurants and its "love bridge" full of padlocks, it is the place where the historic center became a promenade, especially on Fridays at dusk.', importancia_en = 'The most important pedestrian public space in Cali; connecting axis of the historic center on the banks of the river.', datos_historicos_en = 'Built starting in 2012 within the "Megaobras" program of the administration of Mayor Rodrigo Guerrero, it was inaugurated on May 16, 2013, on the longest urban tunnel in the country.', datos_curiosos_en = ARRAY['The pedestrian promenade extends about 980 meters over the "World Cup Tunnel."', 'Between 6,000 and 7,000 people walk through it every day.', 'His "bridge of love" was filled with padlocks, in the style of the Pont des Arts in Paris.']::text[] WHERE id = 's3';

UPDATE sites SET nombre_en = 'Granada neighborhood', tipo_en = 'Gastronomic Zone', descripcion_en = 'Granada was born as a residential neighborhood at the beginning of the 20th century and over the years it became the most cosmopolitan face of Cali taste. Much of the city''s haute cuisine is concentrated in its tree-lined streets: long-tablecloth restaurants, international proposals, specialty coffees and signature cocktails. It is the "gourmet zone" of Cali and a frequent starting point for gastronomic routes.\n\nBut not everything is a table: Lugar a Dudas, one of the most important contemporary art spaces in the city, operates in a house in the neighborhood. Thus, Granada mixes the pleasure of eating well with a cultural life that filters through restaurants and galleries.', importancia_en = 'The city''s main haute cuisine gastronomic area and the scene of its contemporary culinary scene.', datos_historicos_en = 'Traditional residential neighborhood in the north of Cali, emerged at the beginning of the 20th century, which over time consolidated itself as a gastronomic and nightlife epicenter.', datos_curiosos_en = ARRAY['It concentrates a good part of Cali''s haute cuisine restaurants.', 'It houses the contemporary art space Lugar a Dudas.', 'It is a common starting point for gastronomic tours of the city.']::text[] WHERE id = 's61';

UPDATE sites SET nombre_en = 'Dog Park', tipo_en = 'Gastronomic Zone', descripcion_en = 'What began as a neighborhood park in San Fernando—so curved that they nicknamed it "Parque del Corazón"—is today one of the gastronomic and rumba epicenters of Cali. Its name comes from the statue of "Teddy", a dog much loved by a group of young people in the fifties, whose story ended in tragedy. One of those boys, Víctor Alberto Delgado Mallarino, over the years became director of the National Police and ordered the erection of the monument in 1970 where the remains of the animal rest.\n\nRestaurants, breweries, ice cream parlors, boutiques and bars with a street atmosphere are crowded around the statue almost all week long. During the day it invites you to walk and drink coffee; At night it is one of the most lively rumba areas in the city. A tribute to a dog turned into the bohemian heart of Cali.', importancia_en = 'Bohemian and gastronomic epicenter of San Fernando; emblematic night meeting point of the city.', datos_historicos_en = 'The statue of Teddy the dog was installed in 1970 by Víctor Alberto Delgado Mallarino, in a traditional park in the San Fernando neighborhood that, over time, became a gastronomy and nightlife area.', datos_curiosos_en = ARRAY['The park was previously called "Heart Park" because of its shape.', 'Under the statue rest the remains of the dog Teddy.', 'It is close to the salsotecas on Calle 5 and Loma de la Cruz.']::text[] WHERE id = 's24';